&quot;vexide::devices&quot; *
&quot;vexide::devices::smart::Motor&quot;
&quot;vexide&quot; -&gt; [ &quot;devices&quot;, &quot;fs&quot; ]
&quot;vexide::devices&quot;
&quot;vexide::devices&quot; -&gt; [ &quot;smart&quot;, &quot;adi&quot; ]
