  "main.rs": "use std::path::Path;
use anyhow::Result;
use async_trait::async_trait;

// To make a trait with async methods dyn compatible (object safe), 
// we use the `async_trait` crate. 
// 
// Rust does not yet natively support `async fn` in traits for dynamic dispatch 
// because the compiler doesn't know the size of the returned Future at compile time.
// This macro solves it by boxing the Future, making it a trait object itself.

#[async_trait]
pub trait RemoteActions {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()>;
    async fn remove_repo(&mut self, path: &Path) -> Result<()>;
    async fn add_repo(&mut self, path: &Path) -> Result<()>;
    fn get_element(&self, num: usize) -> Result<String>;
}

// --- Production Implementation ---

struct ProductionRemote;

#[async_trait]
impl RemoteActions for ProductionRemote {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()> {
        println!("[Prod] Moving {:?} to {:?}", from, to);
        // Simulate IO work
        tokio::time::sleep(std::time::Duration::from_millis(10)).await;
        Ok(())
    }

    async fn remove_repo(&mut self, path: &Path) -> Result<()> {
        println!("[Prod] Removing {:?}", path);
        tokio::time::sleep(std::time::Duration::from_millis(10)).await;
        Ok(())
    }

    async fn add_repo(&mut self, path: &Path) -> Result<()> {
        println!("[Prod] Adding {:?}", path);
        tokio::time::sleep(std::time::Duration::from_millis(10)).await;
        Ok(())
    }

    fn get_element(&self, num: usize) -> Result<String> {
        Ok(format!("Production Item {}", num))
    }
}

// --- Noop/Mock Implementation for Testing ---

struct NoopRemote;

#[async_trait]
impl RemoteActions for NoopRemote {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()> {
        println!("[Noop] Skipping move from {:?} to {:?}", from, to);
        Ok(())
    }

    async fn remove_repo(&mut self, path: &Path) -> Result<()> {
        println!("[Noop] Skipping remove {:?}", path);
        Ok(())
    }

    async fn add_repo(&mut self, path: &Path) -> Result<()> {
        println!("[Noop] Skipping add {:?}", path);
        Ok(())
    }

    fn get_element(&self, num: usize) -> Result<String> {
        Ok(format!("Noop Item {}", num))
    }
}

// --- The Consumer (Strategy Pattern) ---

// This function accepts a `dyn RemoteActions`, proving it is object safe.
async fn run_sync_process(mut remote: Box<dyn RemoteActions>) {
    let path_a = Path::new("/repo/old");
    let path_b = Path::new("/repo/new");

    println!("Starting sync process...");

    if let Err(e) = remote.add_repo(path_a).await {
        eprintln!("Error adding repo: {}", e);
    }

    if let Err(e) = remote.change_path(path_a, path_b).await {
        eprintln!("Error changing path: {}", e);
    }

    match remote.get_element(1) {
        Ok(s) => println!("Metadata: {}", s),
        Err(e) => eprintln!("Error getting element: {}", e),
    }

    println!("Sync process finished.\n");
}

#[tokio::main]
async fn main() {
    // Scenario 1: Running with the Noop strategy (e.g., for testing)
    println!("--- Running Test Strategy ---");
    let noop_strategy: Box<dyn RemoteActions> = Box::new(NoopRemote);
    run_sync_process(noop_strategy).await;

    // Scenario 2: Running with the Production strategy
    println!("--- Running Production Strategy ---");
    let prod_strategy: Box<dyn RemoteActions> = Box::new(ProductionRemote);
    run_sync_process(prod_strategy).await;
}
"
}
