  "main.rs": "// A simple implementation of a const-compatible PRNG.
// We use SplitMix64 here because it is simple to implement and provides
// good enough distribution for Zobrist hashing, and fits entirely in const fn.
pub struct ConstRng {
    state: u64,
}

impl ConstRng {
    /// Create a new RNG instance.
    const fn new(seed: u64) -> Self {
        Self { state: seed }
    }

    /// Generate the next u64 in the sequence.
    const fn next_u64(&mut self) -> u64 {
        // SplitMix64 constants and algorithm
        self.state = self.state.wrapping_add(0x9e3779b97f4a7c15);
        let mut z = self.state;
        z = (z ^ (z >> 30)).wrapping_mul(0xbf58476d1ce4e5b9);
        z = (z ^ (z >> 27)).wrapping_mul(0x94d049bb133111eb);
        z ^ (z >> 31)
    }
}

pub static ZOBRIST_SEEDS: [u64; 781] = generate_zobrist_seeds();

const fn generate_zobrist_seeds() -> [u64; 781] {
    let mut result = [0; 781];
    // Initialize the PRNG with your desired seed.
    // Note: This uses SplitMix64, so the sequence will differ from ChaCha8Rng.
    let mut rng = ConstRng::new(4174800045971885562);

    let mut i = 0;
    while i < 781 {
        result[i] = rng.next_u64();
        i += 1;
    }
    result
}

fn main() {
    // Verify that the generation happened at compile time and is accessible.
    println!("Generated {} Zobrist seeds.", ZOBRIST_SEEDS.len());
    println!("First few seeds:");
    for i in 0..5 {
        println!("ZOBRIST_SEEDS[{}] = {}", i, ZOBRIST_SEEDS[i]);
    }
}
