use std::path::Path;

// 1. Apply the #[async_trait] attribute to the trait definition.
// This macro converts the async methods to return Pin<Box<dyn Future...>>
// which has a known size at compile time, thus making the trait dyn compatible.
#[async_trait]
pub trait RemoteActions {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()>;
    async fn remove_repo(&mut self, path: &Path) -> Result<()>;
    async fn add_repo(&mut self, path: &Path) -> Result<()>;

    // Regular methods work fine alongside async methods.
    fn get_element(&self, num: usize) -> Result<String>;
}

// --- Production Implementation ---
pub struct ProdActions;

#[async_trait]
impl RemoteActions for ProdActions {
    async fn change_path(&mut self, _from: &Path, _to: &Path) -> Result<()> {
        println!("ProdActions: Changing path...");
        Ok(())
    }

    async fn remove_repo(&mut self, _path: &Path) -> Result<()> {
