// Middleware to check the Origin header
async fn origin_check_middleware<B>(
    req: Request<B>,
    next: Next<B>,
) -> Result<Response, StatusCode> {
    // Check if the Origin header exists and matches the allowed origin
    let origin = req.headers().get(header::ORIGIN);

    match origin {
        Some(origin_val) => {
            if origin_val == ALLOWED_ORIGIN {
                // Origin matches, proceed to the handler
                Ok(next.run(req).await)
            } else {
                // Origin mismatch, block the request
