            // If it's missing, it might be a non-browser client or a malicious request.
            // Depending on your use case, you might allow this or block it.
            // Here we block it to be strict about "coming from a specific website".
            eprintln!("Blocked request with missing Origin header");
            Err(StatusCode::FORBIDDEN)
        }
    }
