    }

    // Cleanup temporary files
    fs::remove_file("a.json")?;
    fs::remove_file("b.json")?;

    Ok(())
}

/// Recursively traverses the JSON value and resolves any `$ref` objects found.
fn resolve_refs(value: &mut Value) -> Result<(), Box<dyn std::error::Error>> {
    match value {
        Value::Object(map) => {
            // Check if this map is a reference object (contains only "$ref")
            if map.len() == 1 && map.contains_key("$ref") {
                let ref_str = map["$ref"].as_str().ok_or("Invalid $ref string")?;
                *value = resolve_ref(ref_str)?;
            } else {
                // Otherwise, recurse into children
                for val in map.values_mut() {
                    resolve_refs(val)?;
                }
            }
        }
        Value::Array(arr) => {
            for val in arr.iter_mut() {
                resolve_refs(val)?;
            }
        }
        _ => {}
    }
    Ok(())
}

/// Resolves a specific reference string (e.g., "./a.json#/p_list").
fn resolve_ref(ref_str: &str) -> Result<Value, Box<dyn std::error::Error>> {
    // Split the reference into file path and JSON pointer
    let parts: Vec<&str> = ref_str.splitn(2, '#').collect();
    let file_path = parts[0];

    // Read the referenced file
    let content = fs::read_to_string(file_path)?;
    let mut json: Value = serde_json::from_str(&content)?;

    // If a JSON pointer is provided (e.g., "/p_list"), traverse to it
    if parts.len() > 1 && !parts[1].is_empty() {
        let pointer = parts[1];
        // serde_json::Value::pointer requires a string starting with '/'
        if let Some(target) = json.pointer(pointer) {
            Ok(target.clone())
        } else {
            Err(format!("Pointer '{}' not found in {}", pointer, file_path).into())
        }
    } else {
        Ok(json)
    }
}
