pub struct Event(String);

pub fn events_channel() -> (EventSender, EventStreamFactory, CancellationToken) {
    let (tx, _) = channel(20);
    // Create a token that we can use to signal shutdown
    let shutdown_token = CancellationToken::new();

    (
        EventSender { tx: tx.clone() },
        EventStreamFactory {
            tx,
            shutdown_token: shutdown_token.clone(),
        },
        shutdown_token,
    )
