    }
}

#[derive(Clone)]
pub struct EventStreamFactory {
    tx: Sender<Event>,
    shutdown_token: CancellationToken,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl futures::Stream<Item = Result<Event, RecvError>> + Send {
        // Clone the token for use in the stream combinator
        let token = self.shutdown_token.clone();

        BroadcastStream::new(self.tx.subscribe())
            // take_until will end the stream when the token is cancelled
            .take_until(token.cancelled())
            .filter_map(|event| match event {
                Ok(event) => Some(Ok(event)),
                // BroadcastStream returns Err(Lagged) if the consumer is too slow.
                // We treat Lagged errors as non-fatal for this example, but you might want to handle them.
                // We also treat the Closed error here, though take_until handles the shutdown logic mostly.
                Err(_) => Some(Err(RecvError::Closed)),
            })
    }
}

// --- Main Demo ---

#[tokio::main]
