    // 2. Simulate cloning the sender 'everywhere'
    let sender1 = sender.clone();
    let sender2 = sender.clone();
    let _senders_in_use = vec![sender1, sender2]; // These exist and keep the channel 'open'

    // 3. Spawn a task that consumes the stream (e.g., your SSE connection)
    let stream_handle = tokio::spawn(async move {
        println!("Stream consumer started.");
        let mut stream = factory.all_events();

        // Using futures::StreamExt::next
        while let Some(result) = stream.next().await {
            match result {
                Ok(event) => println!("Received: {:?}", event),
                Err(e) => println!("Stream error: {:?}", e),
            }
        }
        println!("Stream consumer finished (Shutdown signal received).");
    });

    // 4. Send some events to prove it works
    sender.send(Event("Event 1".into()));
    tokio::time::sleep(Duration::from_millis(100)).await;
    sender.send(Event("Event 2".into()));
    tokio::time::sleep(Duration::from_millis(100)).await;

    println!("Triggering global shutdown via CancellationToken...");

    // 5. Shutdown!
    // Instead of trying to drop all cloned senders, we just cancel the token.
    // The `take_until` combinator sees this and ends the stream.
    shutdown_token.cancel();

    // Wait for the consumer to finish
    stream_handle.await.unwrap();

