# On the actual rp2040 target (thumbv6m-none-eabi), you would typically depend on
# your HAL (e.g., rp2040-hal) which provides the critical-section implementation.
critical-section = { version = "1.1", features = ["std"] }
",
  "main.rs": "use core::sync::atomic::{AtomicUsize, Ordering};

/// A structure mimicking the user's scenario.
struct ChannelManager {
    // In the user's original code, this was atomic-polyfill::AtomicUsize.
    // It is now core::sync::atomic::AtomicUsize.
    channel_index: AtomicUsize,
}

impl ChannelManager {
    pub fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Replaces atomic-polyfill::AtomicUsize::fetch_add.
    /// 
    /// Q: What is the correct Ordering and why?
    /// 
    /// A: Ordering::Relaxed is the correct ordering to use here.
    /// 
    /// Reasoning:
    /// 1. Atomicity: On thumbv6m (Cortex-M0+), the CPU lacks hardware atomic
    ///    Read-Modify-Write (RMW) instructions (like LDREX/STREX on M3/M4).
    ///    `critical_section::with` provides atomicity by disabling interrupts
    ///    (and acquiring a hardware spinlock on RP2040 for multi-core safety).
    ///    This ensures the load and store happen as an indivisible block.
    ///
    /// 2. Memory Ordering: The `Ordering` argument dictates visibility of side-effects
    ///    to other threads/cores and reordering of instructions.
    ///    - The original code requested `Ordering::Relaxed`. This guarantees atomicity
    ///      but imposes no ordering constraints on other memory accesses.
    ///    - By using `Ordering::Relaxed` on the inner load/store, we faithfully replicate
    ///      the original behavior. 
    ///    - Using stronger orderings (like Acquire/Release) inside the critical section
    ///      would introduce unnecessary memory barriers, making the operation slower
    ///      and stronger than the original code intended.
    ///
    /// Note: The critical section itself acts as a barrier (Acquire on enter, Release on exit)
    /// relative to the critical section lock, which is sufficient for the safety of the
    /// operation itself.
    pub fn increment_index(&self) -> usize {
        critical_section::with(|_| {
            // Load the current value.
            // Relaxed is sufficient because the critical section handles the atomicity.
            let old_val = self.channel_index.load(Ordering::Relaxed);

            // Perform the modification.
            let new_val = old_val + 1;

            // Store the new value.
            // Relaxed is sufficient here for the same reason.
            self.channel_index.store(new_val, Ordering::Relaxed);

            // Return the old value, matching fetch_add semantics.
            old_val
        })
    }
}

fn main() {
    let manager = ChannelManager::new();

    println!("Testing atomic replacement logic...");

    let index = manager.increment_index();
    println!("First call: index = {} (expected 0)", index);
    assert_eq!(index, 0);

    let index = manager.increment_index();
    println!("Second call: index = {} (expected 1)", index);
    assert_eq!(index, 1);

    println!("Success! Logic is correct.");
}
"
}
