fn default_false() -> bool { false }

// --- Filtering Logic ---

/// The core trait for filtering.
/// Returns true if `self` satisfies the conditions set in `filter`.
pub trait FilterMatch {
    fn matches_filter(&self, filter: &Self) -> bool;
}

/// Helper function to compare Optional fields.
/// If the filter is None, it acts as a wildcard (always matches).
/// If filter is Some, self must be Some and the values must match.
fn matches_option<T: FilterMatch>(obj: &Option, filter: &Option) -> bool {
    match (obj, filter) {
        // No filter constraint for this field -> Match
        (_, None) => true,
        // Filter requires a value, but object has none -> Fail
        (None, Some(_)) => false,
        // Both have values -> Delegate to the inner type's matching logic
        (Some(obj_val), Some(filter_val)) => obj_val.matches_filter(filter_val),
    }
}

// --- Trait Implementations ---

// Implementation for simple leaf types (Stress, Gender, String, etc.)
// For these types, we just want exact equality if the filter is present.
impl FilterMatch for Stress {
    fn matches_filter(&self, filter: &Self) -> bool {
        self == filter
    }
}

impl FilterMatch for Gender {
    fn matches_filter(&self, filter: &Self) -> bool {
        self == filter
    }
}

impl FilterMatch for String {
    fn matches_filter(&self, filter: &Self) -> bool {
        self == filter
    }
}

// Implementation for a nested struct (NounData)
// This is where the recursion happens. We check fields manually.
impl FilterMatch for NounData {
    fn matches_filter(&self, filter: &Self) -> bool {
        // Check recursive Option<String>
        if !matches_option(&self.plural, &filter.plural) {
            return false;
        }

        // Check recursive Option<Gender>
        if !matches_option(&self.gender, &filter.gender) {
            return false;
        }

        // Check primitive bool: 
        // If the filter sets it to 'true', the object must be 'true'.
        // If the filter is 'false' (default), we consider it a wildcard.
        if filter.is_uncountable && !self.is_uncountable {
            return false;
        }

        true
    }
}

impl FilterMatch for VerbData {
    fn matches_filter(&self, filter: &Self) -> bool {
        if filter.transitive && !self.transitive {
            return false;
        }
        true
    }
}

// Implementation for the root struct (DictWordMetadata)
impl FilterMatch for DictWordMetadata {
    fn matches_filter(&self, filter: &Self) -> bool {
        // 1. Check Optional Nested Structs
        if !matches_option(&self.noun, &filter.noun) {
            return false;
        }
        if !matches_option(&self.verb, &filter.verb) {
            return false;
        }

        // 2. Check Optional Primitive/Enum fields
        if !matches_option(&self.stress, &filter.stress) {
            return false;
        }
        if !matches_option(&self.gender, &filter.gender) {
            return false;
        }

        // 3. Check flat primitive fields
        // Convention: false (default) means "ignore", true means "must be true"
        if filter.preposition && !self.preposition {
            return false;
        }

        true
    }
}

// --- Main Demonstration ---

