    let container_client = blob_service.container_client(container_name);

    // 3. Concurrency Configuration
    // C# uses `Environment.ProcessorCount`. We use `available_parallelism` to match hardware capabilities.
    // This limits the number of concurrent network requests, preventing resource exhaustion.
    let concurrency_limit = std::thread::available_parallelism()
        .map(|p| p.get())
        .unwrap_or(4);

    println!("[Rust] Starting download with concurrency: {}", concurrency_limit);

    // 4. Process both prefixes in parallel (similar to C# Task.WhenAll / FetchAllTrades)
    let (trades_opt, trades_fut) = futures::join!(
        process_prefix(&container_client, prefix_opt, concurrency_limit),
        process_prefix(&container_client, prefix_fut, concurrency_limit)
    );

    let total_trades = trades_opt.len() + trades_fut.len();

    println!("----------------------------------------------------------------");
    println!("[Rust] Total items processed: {}", total_trades);
    println!("[Rust] Total execution time: {:.2} seconds", start_total.elapsed().as_secs_f32());

    Ok(())
}

async fn process_prefix(
    container_client: &ContainerClient,
    prefix: String,
    concurrency: usize,
) -> Vec<TradeData> {
    if prefix.is_empty() {
        return vec![];
    }

    // 1. List Blobs
    // We collect blob names first. This is fast and separates listing from downloading.
    // The C# code does `blobItems.Add` loop before `Parallel.ForEachAsync`.
    let list_stream = container_client
        .list_blobs()
        .prefix(prefix.clone())
        .into_stream();

    let blob_names: Vec<String> = list_stream
        .try_concat()
        .await
        .unwrap_or_default()
        .into_iter()
        .map(|blob| blob.name)
        .collect();

    // 2. Download and Parse in Parallel with Bounded Concurrency
    // The original Rust code used `FuturesUnordered` which spawns unlimited concurrency (1000 tasks).
    // This causes network saturation and context switching overhead.
    // C# `Parallel.ForEachAsync` limits concurrency to `MaxDegreeOfParallelism`.
    // We use `buffer_unordered` to achieve the same effect.
    let trades: Vec<TradeData> = futures::stream::iter(blob_names)
        .map(|blob_name| {
            let client = container_client.blob_client(&blob_name);
            async move {
                // `get_content` downloads the entire blob into Bytes.
                match client.get_content().await {
                    Ok(data) => {
                        // Parse JSON
                        match serde_json::from_slice::<TradeData>(&data) {
                            Ok(trade) => Some(trade),
                            Err(e) => {
                                eprintln!("Failed to parse {}: {}", blob_name, e);
                                None
                            }
                        }
                    }
                    Err(e) => {
                        eprintln!("Failed to download {}: {}", blob_name, e);
                        None
                    }
                }
            }
        })
        .buffer_unordered(concurrency) // KEY FIX: Limits concurrent requests
        .filter_map(|x| async { x })
        .collect()
        .await;

    trades
}
"
}
