        if elapsed < frame_duration {
            std::thread::sleep(frame_duration - elapsed);
        }
    }

    // Restore cursor on exit
    let stdout = io::stdout();
    let mut handle = stdout.lock();
    write!(handle, "\x1b[?25h").unwrap();
