                // Read the current target
                if let Some(mut target_signal) = *drag.active_target.read() {
                    let (off_x, off_y) = *drag.offset.read();
                    let coords = e.client_coordinates();

                    // Calculate new position
                    let new_x = coords.x as i64 - off_x;
                    let new_y = coords.y as i64 - off_y;

                    // Update the child component's signal directly.
                    // This causes ONLY that specific child to re-render.
                    target_signal.set(PointData { x: new_x, y: new_y });
                }
            },
            onmouseup: move |_| {
                // Stop dragging
                drag.active_target.set(None);
            },
            onmouseleave: move |_| {
                // Stop dragging if mouse leaves the window
                drag.active_target.set(None);
            },

            {children}
        }
    }
