  "main.rs": "use rayon::prelude::*;
use std::f64;

#[derive(Debug, Default, Clone)]
struct B {
    r: Vec<f64>,
    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>,
}

impl B {
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];

        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    pub fn build_lists(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;

        // 1. PARALLEL READ-ONLY PHASE
        // We compute the neighbor indices in parallel. 
        // To satisfy Rust's safety rules:
        // - We use `par_iter` (immutable access) to read elements for criterion checks.
        // - We only iterate the upper triangle (j > i). 
        //   This cuts work in half and avoids double-checking pairs (i,j) and (j,i).
        // - We collect the pairs into a list. This avoids aliasing issues 
        //   (trying to write to `j` while `i` is being processed in parallel).
        let pairs: Vec<(usize, usize)> = self.elems
            .par_iter()
            .enumerate()
            .flat_map(|(i, elem_i)| {
                // Access the slice of elements after index i
                // Note: We capture `self.elems` immutably here, which is safe with `par_iter`
                // because `par_iter` guarantees the iterators don't mutate the source.
                // However, accessing `self.elems` inside the closure while iterating it
                // requires the closure to capture the slice, not the struct.
                // Rayon handles this via `par_iter` which yields references.
                // To look at 'other' elements, we access the slice by index.
                // We can do this safely because `par_iter` implies shared references.

                // We create an iterator over the indices j > i
                (i + 1..nelems).into_par_iter().filter_map(move |j| {
                    let elem_j = &self.elems[j];
                    if elem_i.criterion(elem_j) < cutoff {
                        Some((i, j))
                    } else {
                        None
                    }
                })
            })
            .collect();

        // 2. AGGREGATION PHASE
        // Initialize empty neighbor lists.
        let mut neighbors = vec![Vec::new(); nelems];

        // Populate lists based on the pairs found.
        // We add j to i's list AND i to j's list (symmetric update).
        // This is very fast and done sequentially here, but could be parallelized 
        // if the list of pairs was astronomically large.
        for (i, j) in pairs {
            neighbors[i].push(j);
            neighbors[j].push(i);
        }

        // 3. WRITE PHASE
        // Assign the computed lists back to the elements in parallel.
        self.elems
            .par_iter_mut()
            .zip(neighbors)
            .for_each(|(elem, nb_list)| {
                elem.nb = nb_list;
            });
    }
}

fn main() {
    let mut a = A {
        elems: vec![
            B { r: vec![0.0, 0.0, 0.0], ..Default::default() },
            B { r: vec![1.0, 0.0, 0.0], ..Default::default() }, // Close to 0
            B { r: vec![50.0, 50.0, 50.0], ..Default::default() }, // Far away
            B { r: vec![0.0, 1.0, 0.0], ..Default::default() }, // Close to 0
        ],
        cutoff: 10.0,
    };

    println!("Building lists...");
    a.build_lists();

    for (i, elem) in a.elems.iter().enumerate() {
        println!("Element {} neighbors: {:?}", i, elem.nb);
    }

    // Verify correctness
    // 0 is close to 1, 3. (Neighbors: 1, 3)
    // 1 is close to 0, 3. (Neighbors: 0, 3)
    // 2 is far. (Neighbors: [])
    // 3 is close to 0, 1. (Neighbors: 0, 1)
    assert_eq!(a.elems[0].nb, vec![1, 3]);
    assert_eq!(a.elems[1].nb, vec![0, 3]);
    assert_eq!(a.elems[2].nb, vec![]);
    assert_eq!(a.elems[3].nb, vec![0, 1]);

    println!("Assertions passed!");
}
