pub trait FilterMatch {
    /// Returns true if `self` matches the `filter`.
    /// Fields in `filter` that are 'empty' (None or default) are ignored.
    /// Fields in `filter` that are 'set' must be equal to the corresponding field in `self`.
    fn matches_filter(&self, filter: &Self) -> bool;
