macro_rules! impl_filter_match {
    ($struct_name:ident { $($field:ident),+ $(,)? }) => {
        impl FilterMatch for $struct_name {
            fn matches_filter(&self, filter: &Self) -> bool {
                $(
                    if !FilterMatch::is_set(&filter.$field) {
                        continue;
                    }
                    if !FilterMatch::matches_filter(&self.$field, &filter.$field) {
                        return false;
                    }
