  "main.rs": "/*
Solution to the enum_dispatch crate separation dilemma.

Problem:
The user wants to use `enum_dispatch` to implement a trait `Rest` (defined in crate `al`)
for an enum `Item` (defined in crate `bl`). 
However, `enum_dispatch` requires the trait and the enum to be in the same crate.
Moving the enum to `al` creates a circular dependency (`al` -> `il` -> `al`).

Solution:
We implement a custom Dispatch Macro in the Abstract Layer (`al`).
1. `al` defines the `Rest` trait and a macro `dispatch_rest!`.
2. `al` defines the macro to implement `Rest` for any enum by forwarding calls to variants.
3. `il` defines concrete types (`Foo`, `Boo`) implementing `Rest`.
4. `bl` defines the enum `Item` and invokes `dispatch_rest!(Item, Foo, Boo);`.

This preserves the dependency graph: bl -> al, bl -> il, il -> al.
No cycles, and `bl` does not need to manually implement 20 methods.
*/

// ==========================================
// Crate 'al' (Abstract Layer)
// ==========================================
mod al {
    // The trait with many methods
    pub trait Rest {
        fn get(&self) -> String;
        fn post(&self, data: &str) -> String;
        fn delete(&self) -> String;
        // ... imagine 20 methods here ...
    }

    // A macro defined in 'al' that knows how to implement 'Rest' for an enum.
    // This replaces #[enum_dispatch] but works across crates.
    #[macro_export]
    macro_rules! dispatch_rest {
        // $Enum: The enum type name
        // $($Variant:ident),*: The list of variant names
        ($Enum:ident, $($Variant:ident),*) => {
            impl $crate::al::Rest for $Enum {
                fn get(&self) -> String {
                    match self {
                        $( $Enum::$Variant(inner) => inner.get(), )*
                    }
                }
                fn post(&self, data: &str) -> String {
                    match self {
                        $( $Enum::$Variant(inner) => inner.post(data), )*
                    }
                }
                fn delete(&self) -> String {
                    match self {
                        $( $Enum::$Variant(inner) => inner.delete(), )*
                    }
                }
                // Expand this macro block to cover all 20 methods
            }
        };
    }
}

// ==========================================
// Crate 'il' (Implementation Layer)
// ==========================================
mod il {
    use crate::al::Rest;

    pub struct Foo;
    impl Rest for Foo {
        fn get(&self) -> String { "Foo GET".to_string() }
        fn post(&self, data: &str) -> String { format!("Foo POST: {}", data) }
        fn delete(&self) -> String { "Foo DELETE".to_string() }
    }

    pub struct Boo;
    impl Rest for Boo {
        fn get(&self) -> String { "Boo GET".to_string() }
        fn post(&self, data: &str) -> String { format!("Boo POST: {}", data) }
        fn delete(&self) -> String { "Boo DELETE".to_string() }
    }
}

// ==========================================
// Crate 'bl' (Business Layer)
// ==========================================
mod bl {
    use crate::al::Rest;
    use crate::il::{Foo, Boo};
    // Import the macro defined in 'al'
    use crate::dispatch_rest;

    // Define the enum wrapping the implementations
    pub enum Item {
        Foo(Foo),
        Boo(Boo),
    }

    // Use the macro to implement Rest for Item.
    // This is the only line needed in 'bl' to implement all 20 methods.
    dispatch_rest!(Item, Foo, Boo);
}

// ==========================================
// Main Execution
// ==========================================
fn main() {
    use crate::al::Rest;
    use crate::bl::Item;
    use crate::il::{Foo, Boo};

    let item_foo = Item::Foo(Foo);
    let item_boo = Item::Boo(Boo);

    // Static dispatch happens here!
    println!("{}", item_foo.get());
    println!("{}", item_boo.post("hello world"));
}
"
}
