  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};
use futures::task::noop_waker;

// The result enum requested
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

// The function to synchronously check a future.
// We add the `Unpin` bound to safely poll the future via a mutable reference.
// Without Unpin, we would need unsafe code or ownership of the future to pin it.
fn try_poll<X>(future: &mut (impl Future<Output = X> + Unpin)) -> TryPollResult<X> {
    // Create a "no-op" waker. 
    // Since we are just checking if the future is immediately ready, 
    // we don't need a real waker to schedule a wake-up.
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    // Poll the future
    match Future::poll(Pin::new(future), &mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// A non-async function that executes within an async context (Tokio runtime)
fn sync_function_handling_future() {
    // We need the Tokio handle to spawn tasks from this non-async function.
    // This assumes we are running within a Tokio runtime (which main is).
    let handle = tokio::runtime::Handle::current();

    println!("--- Scenario 1: Future is Ready immediately ---");

    // Create a future that is immediately ready.
    // We use Box::pin to make it Unpin and heap-allocated.
    let mut immediate_fut = Box::pin(async { 42 });

    match try_poll(&mut immediate_fut) {
        TryPollResult::Ready(val) => {
            println!("Future completed synchronously with value: {}", val);
        }
        TryPollResult::Pending => {
            // This branch won't happen for this future
            println!("Future is pending (unexpected)");
        }
    }

    println!("--- Scenario 2: Future is Pending ---");

    // Create a future that requires awaiting (yielding).
    // We Box::pin it to satisfy Unpin requirement.
    let mut pending_fut = Box::pin(async {
        // This causes the future to yield once, making it Pending on the first poll.
        tokio::time::sleep(std::time::Duration::from_millis(10)).await;
        100
    });

    match try_poll(&mut pending_fut) {
        TryPollResult::Ready(val) => {
            println!("Future completed synchronously (unexpected): {}", val);
        }
        TryPollResult::Pending => {
            println!("Future is Pending. Spawning a Tokio task to handle it...");

            // We spawn a task. We must move ownership of the future into the task.
            // Since we only had a mutable reference in try_poll, we still own `pending_fut` here.
            handle.spawn(async move {
                let result = pending_fut.await;
                println!("Future completed asynchronously in spawned task with value: {}", result);
            });
        }
    }
}

#[tokio::main]
async fn main() {
    // Call the non-async function
    sync_function_handling_future();

    // Wait a bit to ensure the spawned task finishes before the program exits
    tokio::time::sleep(std::time::Duration::from_millis(50)).await;
    println!("Done.");
}"
}
