  "main.rs": "use chrono::NaiveDateTime;

/// Parses a LanceDB formatted ISO string (naive datetime) into a Unix timestamp (milliseconds).
/// 
/// LanceDB returns strings like "2025-08-02T17:35:41.409" or "1970-01-01T00:00:00".
/// These are "naive" datetimes (no timezone offset info).
/// 
/// The error `ParseError(NotEnough)` occurs when using `DateTime::parse_from_str` 
/// because that function expects timezone information (like 'Z' or '+00:00') which 
/// LanceDB strings do not provide.
/// 
/// The fix is to use `NaiveDateTime::parse_from_str` instead.
pub fn date_string_to_int(d: &str) -> Result<i64, chrono::ParseError> {
    // The format matches:
    // %Y-%m-%d : Date (e.g., 2025-08-02)
    // T        : Literal separator
    // %H:%M:%S : Time (e.g., 17:35:41)
    // %.f      : Optional decimal seconds (e.g. .409). This handles both cases.
    let format = "%Y-%m-%dT%H:%M:%S%.f";

    // 1. Parse into NaiveDateTime (a date/time without a timezone).
    //    This solves the `ParseError(NotEnough)` issue.
    let naive_dt = NaiveDateTime::parse_from_str(d, format)?;

    // 2. Assume UTC to calculate the timestamp. 
    //    Since LanceDB stored these as integers, they are typically UTC.
    //    .and_utc() attaches the UTC timezone to the naive datetime.
    let datetime_utc = naive_dt.and_utc();

    // 3. Convert to integer.
    //    Using timestamp_millis() to preserve the sub-second precision seen in your data.
    //    If you strictly need seconds, use .timestamp() instead.
    Ok(datetime_utc.timestamp_millis())
}

fn main() {
    let test_dates = [
        "1970-01-01T00:00:00",
        "2025-08-02T17:35:41.409",
        "2025-08-04T01:48:44.017",
        "2025-08-04T23:02:20.584",
        "2025-08-05T00:08:57.350",
        "2025-08-10T18:31:26.628",
    ];

    for d in test_dates.iter() {
        match date_string_to_int(d) {
            Ok(ts) => println!("Parsed '{}' -> Timestamp: {}", d, ts),
            Err(e) => println!("Error parsing '{}': {:?}", d, e),
        }
    }
}
"
}
