/// Middleware to check the Origin header for WebSocket upgrade requests.
async fn ws_origin_check_middleware(
    request: Request,
    next: Next,
) -> Result<Response, StatusCode> {
    // Check if this is a WebSocket upgrade request
    let is_websocket = request.headers()
        .get(UPGRADE)
        .and_then(|v| v.to_str().ok())
        .map(|v| v.to_lowercase() == "websocket")
        .unwrap_or(false);

    if is_websocket {
        // For WebSocket connections, strictly check the Origin header
        let origin = request.headers().get("origin");

        match origin {
            Some(val) if val == ALLOWED_ORIGIN => {
                tracing::info!("WebSocket connection allowed from origin: {:?}", val);
            }
            Some(val) => {
                tracing::warn!("Blocked WebSocket connection from disallowed origin: {:?}", val);
                return Err(StatusCode::FORBIDDEN);
            }
            None => {
                tracing::warn!("Blocked WebSocket connection with missing origin header");
                return Err(StatusCode::FORBIDDEN);
            }
        }
    }

    // Proceed to the handler
    Ok(next.run(request).await)
}

