    group: String,
    kind: String,
}

impl Default for MyDynamicType {
    fn default() -> Self {
        Self {
            group: "my-group".to_string(),
            kind: "my-kind".to_string(),
        }
    }
}

impl Resource for MyResource {
    type DynamicType = MyDynamicType;

    fn group(dt: &Self::DynamicType) -> Cow<'_, str> {
        // Return a reference to the string owned by dt (zero-copy)
        Cow::Borrowed(&dt.group)
    }

    fn kind(dt: &Self::DynamicType) -> Cow<'_, str> {
        // Return a reference to the string owned by dt (zero-copy)
        Cow::Borrowed(&dt.kind)
    }
}

// --- The Solution ---

// The "Magic Sauce" is the `ouroboros` crate. It allows a struct to hold
// both the owner (dynamic_type) and references to that owner (group/kind).
#[self_referencing]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default,
{
    type_: PhantomData<R>,

    // This is the owner of the data.
    dynamic_type: R::DynamicType,

    // These fields borrow from `dynamic_type`. 
    // The crate ensures `dynamic_type` is dropped after these fields.
    #[borrows(dynamic_type)]
    group: Option<Cow<'this, str>>,

    #[borrows(dynamic_type)]
    kind: Cow<'this, str>,

    // This field does not borrow from dynamic_type
    name: String,
}

impl<R: Resource> ResourceRef<R>
where
    R::DynamicType: Default,
{
    pub fn new_named(name: &str) -> Self {
        // We use the builder generated by `#[self_referencing]`
        ResourceRefBuilder {
            type_: PhantomData,
            dynamic_type: R::DynamicType::default(),
            // We define how to construct the borrowed fields inside the closure
            group_builder: |dt| {
                let g = R::group(dt);
                if g.is_empty() {
                    None
                } else {
                    Some(g)
                }
            },
            kind_builder: |dt| R::kind(dt),
            name: name.to_string(),
        }.build()
    }

    pub fn group(&self) -> &str {
        // `with_group` allows access to the borrowed field
        self.with_group(|g| {
            g.as_ref().map(|c| c.as_ref()).unwrap_or("")
        })
    }

    pub fn kind(&self) -> &str {
        self.with_kind(|k| k.as_ref())
    }

    pub fn name(&self) -> &str {
        self.borrow_name()
    }
}

fn main() {
    let resource_ref = ResourceRef::<MyResource>::new_named("my-name");

    println!("Name: {}", resource_ref.name());
    println!("Group: {}", resource_ref.group());
    println!("Kind: {}", resource_ref.kind());

    // Verify that we can still use the struct as a key-like thing
    println!("Struct: {:?}", resource_ref);
}
