use tokio::sync::broadcast::{self, RecvError};
use tokio_stream::wrappers::BroadcastStream;
use tokio_util::sync::CancellationToken;

// --- Your Abstractions (Modified for Shutdown) ---

#[derive(Debug)]
struct Event {
    id: usize,
    message: String,
}

pub fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = broadcast::channel(20);
    // Create a token to signal shutdown
    let shutdown_token = CancellationToken::new();

    (
        EventSender { 
            tx: tx.clone(),
        },
        EventStreamFactory { 
            tx, 
            shutdown_token,
        },
    )
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: broadcast::Sender<Event>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        // We clone tx here to simulate it being "all over the place"
        let _ = self.tx.send(event);
    }
}

pub struct EventStreamFactory {
    tx: broadcast::Sender<Event>,
    shutdown_token: CancellationToken,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl futures::Stream<Item = Result<Event, RecvError>> + Send + use<'_> {
        let token = self.shutdown_token.clone();

        BroadcastStream::new(self.tx.subscribe())
            .filter_map(move |event| {
                // If the token is cancelled, we stop the stream immediately
                if token.is_cancelled() {
                    return None;
                }

                match event {
                    Ok(event) => Some(Ok(event)),
                    // Handling lagging errors or closed channel
                    Err(_) => Some(Err(RecvError::Closed)),
                }
            })
            // take_until automatically ends the stream when the token fires
            .take_until(token.cancelled_owned())
    }

    // A method to trigger the shutdown
    pub fn shutdown(&self) {
        self.shutdown_token.cancel();
    }
}

// --- Main Simulation ---

#[tokio::main]
async fn main() {
    println!("--- Starting Broadcast Shutdown Demo ---");

    let (sender, factory) = events_channel();

    // Spawn a task that consumes the stream (simulating an SSE connection)
    let stream_handle = tokio::spawn(async move {
        println!("Consumer: Started listening...");
        let mut stream = factory.all_events();

        while let Some(result) = stream.next().await {
            match result {
                Ok(event) => println!("Consumer: Received event '{}'...", event.message),
                Err(_) => println!("Consumer: Stream error or closed."),
            }
        }
        println!("Consumer: Stream finished (Shutdown signal received).");
    });

    // Simulate the Sender being cloned and used elsewhere
    let sender_clone = sender.clone();

    // Send some data
    sender.send(Event { id: 1, message: "Hello".into() });
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

    sender_clone.send(Event { id: 2, message: "World".into() });
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

    println!("MAIN: Triggering shutdown (dropping logical connection)...");

    // SHUTDOWN LOGIC:
    // Instead of trying to hunt down every cloned Sender to drop them,
    // we signal the CancellationToken. The Stream sees this signal 
    // and terminates gracefully.
    factory.shutdown();

    // Wait for the consumer to finish
    let _ = stream_handle.await;

    println!("MAIN: Service shutdown complete.");
}
