// ------------------------------------------------------------------------------------------------
// 2. The Core Logic: Custom AssetReader
// ------------------------------------------------------------------------------------------------

/// A custom AssetReader that handles paths pointing inside zip files.
/// Syntax: `path/to/archive.zip/path/inside/zip.png`
pub struct LazyArchiveReader {
    root: PathBuf,
    // We wrap the default file reader to handle non-zip requests normally
    default_reader: bevy::asset::io::FileAssetReader,
}

impl LazyArchiveReader {
    pub fn new(root: PathBuf) -> Self {
        let default_reader = bevy::asset::io::FileAssetReader::new(&root);
        Self { root, default_reader }
    }

    /// Helper to check if the path requested is inside an archive.
    /// Returns (path_to_archive, path_inside_archive) if it is.
    fn parse_archive_path(&self, path: &Path) -> Option<(PathBuf, PathBuf)> {
        // We look for a file segment that ends with .zip
        let mut current_path = self.root.clone();
        let mut archive_internal_path = PathBuf::new();

        for component in path.components() {
            current_path.push(&component);

            if current_path.extension().map_or(false, |ext| ext == "zip") {
                if current_path.exists() {
                    // Found the archive file. The rest of the components are inside the zip.
                    let remaining: PathBuf = path.strip_prefix(&current_path.strip_prefix(&self.root).unwrap()).unwrap().to_path_buf();
                    return Some((current_path, remaining));
                }
            }
        }
        None
    }
}

#[async_trait]
impl AssetReader for LazyArchiveReader {
    async fn read(&self, path: &Path) -> Result<Box<Reader<'static>>, AssetReaderError> {
        // 1. Check if this is an archive path
        if let Some((archive_path, internal_path)) = self.parse_archive_path(path) {
            // println!("Lazy loading: {:?} from {:?}", internal_path, archive_path);

