            // NOTE: For high performance with thousands of files, you might cache the ZipArchive 
            // in an LRU cache or similar, but for this demo we open it on demand.
            let file = File::open(&archive_path).map_err(|e| AssetReaderError::Io(e))?;
            let mut archive = ZipArchive::new(file).map_err(|e| AssetReaderError::Io(std::io::Error::new(std::io::ErrorKind::Other, e)))?;

            // Extract the specific file
            let internal_str = internal_path.to_string_lossy();
            let mut zip_file = archive.by_name(&internal_str)
