            // Movement::BackwardChar(n) selects the n characters before the cursor.
            // Cmd::Replace deletes the selection and inserts the new text.
            // The cursor is automatically positioned after the inserted text.
            let movement = Movement::BackwardChar(space_count as RepeatCount);
            Some(Cmd::Replace(movement, Some(insert_str)))
        } else {
            // If no whitespace, just insert the character normally.
            Some(Cmd::Insert(1, insert_str))
        }
    }
