use std::pin::Pin;
use std::task::{Context, Poll};
use futures::task::noop_waker;

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Attempts to poll a future synchronously.
/// 
/// Note: We take ownership of the future (rather than &mut) because if it is Pending,
/// we must move it into the spawned task to continue polling it.
/// Rust's ownership model prevents us from moving a future out of a mutable reference.
fn try_poll<X>(future: impl Future<Output = X> + Send + 'static) -> TryPollResult<X> 
where 
    X: Send + 'static
{
    // Create a "noop" waker. 
    // This satisfies the API requirements for polling, but does nothing when woken.
    // This is acceptable because we only poll once synchronously. 
    // If the future returns Pending, we hand it off to Tokio which will replace 
    // the waker with a real one during the subsequent poll inside the async task.
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    // Pin the future on the heap so we can poll it.
    // Box::pin is safe here and handles the Unpin requirement for polling.
    let mut future = Box::pin(future);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(result) => TryPollResult::Ready(result),
        Poll::Pending => {
            // The future is not ready. 
            // We spawn a Tokio task to await the future to completion.
            tokio::spawn(async move {
                let _result = future.await;
                // Logic to handle the result could go here
            });
            TryPollResult::Pending
        }
    }
}

#[tokio::main]
async fn main() {
    // Case 1: A future that is immediately ready
    println!("--- Testing Ready Future ---");
    let ready_future = async { 42 };

    match try_poll(ready_future) {
        TryPollResult::Ready(val) => println!("Future was ready immediately! Value: {}", val),
        TryPollResult::Pending => println!("Future is pending (spawned task)"),
    }

    // Case 2: A future that is not ready (requires sleep)
    println!("\n--- Testing Pending Future ---");
    // We wrap the sleep and value return to ensure the type system is happy
    let pending_future = async {
        tokio::time::sleep(std::time::Duration::from_millis(50)).await;
        println!("(Inside spawned task): Finished sleeping!");
        100
    };

    match try_poll(pending_future) {
        TryPollResult::Ready(_) => println!("Future was ready immediately (unexpected)"),
        TryPollResult::Pending => println!("Future is pending. Task has been spawned."),
    }

    // Wait a bit to ensure the spawned task completes before the program exits
    tokio::time::sleep(std::time::Duration::from_millis(200)).await;
    println!("\nDone.");
}
"
}
