    // row_mean_tr() returns a Row Vector (1 x k) containing the mean of each column.
    let mean = matrix.row_mean_tr();

    println!("\nColumn Means (1x4):\n{}", mean);

    // 3. Subtract the mean from the matrix
    // nalgebra does not support NumPy-style broadcasting in its standard arithmetic operators.
    // Attempting `matrix - mean` results in a dimension mismatch panic because it expects
    // both operands to have the same dimensions.
    //
    // To broadcast the subtraction, we iterate over the columns and subtract the
    // corresponding scalar mean from each column vector.
    let mut centered = matrix.clone();

    for i in 0..centered.ncols() {
        // Extract the scalar mean for the i-th column
        let col_mean = mean[i];

        // Subtract the scalar from the entire column vector.
        // nalgebra supports Vector - Scalar operations.
        centered.column_mut(i) -= col_mean;
    }

    println!("\nCentered Matrix:\n{}", centered);

    // 4. Verification
    // The column means of the centered matrix should be approximately zero.
    let new_mean = centered.row_mean_tr();
    println!("\nNew Column Means (approx zero):\n{}", new_mean);
}
