  "main.rs": "use radiate::*;

// In the 'radiate' crate, the Op<T> type is an Enum, not a trait object.
// This means you cannot add custom variants to the Op enum from outside the library.
// To achieve a 'custom operator' like 'sqrt(x) + 1', you have two main options:
// 1. Let the Genetic Program discover it by providing primitives (Add, Sqrt, Const).
// 2. If you need a specific atomic function, you would typically have to fork the crate 
//    or use a different GP library that supports trait-based nodes.
//
// Since we cannot modify the `Op` enum, we will demonstrate the standard approach:
// Providing the necessary building blocks (Add, Sqrt, Constant) so the engine 
// can evolve the equation `sqrt(x) + 1`.

fn main() {
    // 1. Define the training data
    // We want to find the equation: y = sqrt(x) + 1
    let inputs: Vec<Vec<f32>> = (1..=10).map(|x| vec![x as f32]).collect();
    let targets: Vec<f32> = inputs.iter().map(|x| x[0].sqrt() + 1.0).collect();

    // 2. Define the Node Store (The available operations)
    // We give the GP the tools to build the desired function.
    // Notice we include 'sqrt' and 'value' (constants).
    let store = vec![
        (
            NodeType::Vertex, 
            vec![Op::add(), Op::sub(), Op::mul(), Op::sqrt()]
        ),
        (
            NodeType::Leaf, 
            // var(0) represents the input variable x
            // value() allows the GP to pick random constant numbers (like 1.0)
            vec![Op::var(0), Op::value(1.0)] 
        ),
    ];

    // 3. Define the Problem (Fitness Function)
    struct RegressionProblem {
        inputs: Vec<Vec<f32>>,
        targets: Vec<f32>,
    }

    impl Problem<Op<f32>, f32> for RegressionProblem {
        fn evaluate(&self, phenotype: &mut Phenotype<Op<f32>, f32>) {
            let tree = phenotype.genotype();
            let mut total_error = 0.0;

            for (input, target) in self.inputs.iter().zip(self.targets.iter()) {
                // Evaluate the evolved tree with the input
                match tree.eval(input) {
                    Ok(result) => {
                        // Calculate squared error
                        total_error += (result - target).powi(2);
                    },
                    Err(_) => {
                        // Penalize invalid trees (e.g., sqrt of negative)
                        total_error += 1000.0; 
                    }
                }
            }

            // The engine minimizes the score by default
            phenotype.set_score(Score::from(total_error));
        }
    }

    // 4. Setup and Run the Engine
    let problem = RegressionProblem { inputs, targets };

    // Create the Codex (Generator for the GP Trees)
    // We use a TreeCodex which generates random trees from our store
    let codex = TreeCodex::new(3, store)
        .constraints(Constraints::new().constant(0.0..10.0)); // Range for random constants

    // Build the Engine
    let engine = Engine::new()
        .codex(codex)
        .evaluator(&problem)
        .minimize()
        .population_size(100)
        .alterer(
            // Standard GP alterers: Mutation and Crossover
            vec![
                AlterType::Mutator(Mutator::new(0.05)),
                AlterType::Crossover(Crossover::new(0.5))
            ]
        )
        .selector(RouletteSelector::new())
