    let (impl_generics, ty_generics, where_clause) = struct_generics.split_for_impl();

    // Create a unique module name to avoid collisions
    // In a real proc-macro, you might use a uuid or hash
    let mod_name = format_ident!("_foo_impl_check_{}", struct_name.to_string().to_lowercase());

    // 1. Generate the helper module.
    // We use a trait shadowing trick:
    // We define an empty local trait named `Foo`. This shadows the actual `Foo` trait
    // we are implementing. This ensures that `inst.go()` inside the helper
    // NEVER resolves to the trait method we are currently implementing.
    // It can only resolve to an inherent method on the struct.

    let expanded = quote! {
