        mod #mod_name {
            // Import everything from parent. This brings in the Struct and any 
            // dependencies (types, traits for bounds) defined in the parent scope.
            use super::*;

            // SHADOW TRICK: Define a dummy trait with the same name as the target trait.
            // This prevents the real Foo trait from being visible here,
            // stopping the recursion.
            trait Foo {
                fn go(&self) { /* dummy */ }
            }

            // The intermediate function
            #[inline(always)]
