                // It cannot see the trait `Foo` due to shadowing.
                // If inherent `go` does not exist, compilation fails here with 
                // "no method named `go` found".
                inst.go(); 
            }
        }

        // The actual Trait Implementation
        impl #impl_generics Foo for #struct_name #ty_generics #where_clause {
            fn go(&self) {
                // Call the helper function
                #mod_name::go(self);
            }
        }
    };

    expanded
}

