/// Parses a LanceDB formatted ISO string (without timezone) into a Unix timestamp (milliseconds).
/// 
/// LanceDB returns strings like "2025-08-02T17:35:41.409" or "1970-01-01T00:00:00".
/// These lack timezone info, so we parse them as NaiveDateTime and assume UTC.
fn date_string_to_int(d: &str) -> Result<i64, Box<dyn std::error::Error>> {
    // The format matches ISO 8601 without timezone.
    // %Y-%m-%dT%H:%M:%S matches the main time.
    // %.f handles the optional milliseconds part (e.g., .409).
    let format = "%Y-%m-%dT%H:%M:%S%.f";

    // 1. Parse into a NaiveDateTime (a date/time without a timezone)
    let naive_dt = NaiveDateTime::parse_from_str(d, format)?;

    // 2. Assume the time is in UTC and convert to a DateTime<Utc>
    // Since LanceDB stores dates as Unix integers, they are inherently UTC.
    let datetime_utc = Utc.from_utc_datetime(&naive_dt);

    // 3. Return the timestamp in milliseconds
    Ok(datetime_utc.timestamp_millis())
}

