pub trait MatchesFilter {
    /// Returns true if `self` matches the `filter`.
    /// `filter` fields set to `None` (or default) are ignored.
    fn matches_filter(&self, filter: &Self) -> bool;
}

// Implementation for Option<T>
// If filter is None, it matches everything (wildcard).
// If filter is Some(val), self must be Some(other) where other matches val.
impl<T: MatchesFilter> MatchesFilter for Option<T> {
    fn matches_filter(&self, filter: &Self) -> bool {
        match filter {
            None => true, // Filter not specified, so it matches
            Some(filter_val) => {
                match self {
                    None => false, // Filter requires value, but we have none
                    Some(self_val) => self_val.matches_filter(filter_val),
                }
            }
        }
    }
}

// Implementation for leaf types (primitives, enums, etc.)
// We assume standard equality for leaf types.
// Note: For `bool` fields, this means if filter is `false`, target must be `false`.
// To support "wildcard" behavior for bools, they should be wrapped in Option.
impl MatchesFilter for bool {
    fn matches_filter(&self, filter: &Self) -> bool {
        self == filter
    }
}

