    fn matches_filter(&self, filter: &Self) -> bool {
        self == filter
    }
}

impl MatchesFilter for Stress {
    fn matches_filter(&self, filter: &Self) -> bool {
        self == filter
    }
}

impl MatchesFilter for Gender {
    fn matches_filter(&self, filter: &Self) -> bool {
        self == filter
    }
}

impl MatchesFilter for DialectFlags {
    fn matches_filter(&self, filter: &Self) -> bool {
        // If filter is empty (default), ignore. Otherwise check equality.
        // This logic depends on requirements; simple equality used here.
        if filter.0.is_empty() { return true; }
        self == filter
    }
}

impl MatchesFilter for OrthFlags {
    fn matches_filter(&self, filter: &Self) -> bool {
        if filter.0.is_empty() { return true; }
        self == filter
    }
}

// Macro to generate the implementation for Structs
macro_rules! impl_matches_filter {
    ($struct_name:ident { $($field:ident),+ $(,)? }) => {
        impl MatchesFilter for $struct_name {
            fn matches_filter(&self, filter: &Self) -> bool {
                // Check every field. If any field fails to match, return false.
                $(
                    if !MatchesFilter::matches_filter(&self.$field, &filter.$field) {
                        return false;
                    }
                )+
                true
            }
        }
    };
}

