/// Listens for key events. Stops when a message is received on `stop_rx`.
fn yield_keys(sender: Sender<Message>, stop_rx: Receiver<()>) {
    // We use async_stdin() which provides a non-blocking handle to stdin.
    let mut stdin = async_stdin().events();

    loop {
        // 1. Check for stop signal
        if stop_rx.try_recv().is_ok() {
            println!\!"\r[Input Thread] Stop signal received. Exiting...";
            break;
        }

        // 2. Poll for input (non-blocking)
        // Since async_stdin is non-blocking, .next() returns immediately.
        match stdin.next() {
            Some(Ok(event)) => {
                if let termion::event::Event::Key(Key::Char(c)) = event {
