            Some(Err(e)) if e.kind() == ErrorKind::WouldBlock => {
                // No input available right now. Sleep to reduce CPU usage.
                thread::sleep(Duration::from_millis(50));
            }
            Some(Err(_)) => break, // IO Error
            None => break,         // EOF
        }
    }
}

