fn yield_signals(sender: Sender<Message>, stop_rx: Receiver<()>) {
    // Signals::new creates a iterator that can be polled without blocking indefinitely
    // if we use .pending() or just check the iterator in a loop with logic.
    // However, the iterator itself is blocking. We use `pending()` to make it non-blocking.
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();

    loop {
        // 1. Check for stop signal
        if stop_rx.try_recv().is_ok() {
            println!\!"\r[Signal Thread] Stop signal received. Exiting...";
            break;
        }

        // 2. Poll for signals (non-blocking)
        // .pending() returns an iterator over signals that have already been received.
        for sig in signals.pending() {
            if sender.send(Message::Signal(sig)).is_err() {
                return; // Main thread dropped the receiver
            }
        }

        // Sleep to prevent busy-waiting
        thread::sleep(Duration::from_millis(100));
    }
