    let (stop_tx, stop_rx_keys) = mpsc::channel::<()>();
    let stop_rx_signals = stop_rx_keys.clone();

    println!\!"\r--- Event Loop Started ---";
    println!\!"\rPress 'q' to quit via input.";
    println!\!"\rPress Ctrl+C to quit via signal.";

    // Spawn the threads
    let keys_handle = thread::spawn(move || {
        yield_keys(sender.clone(), stop_rx_keys);
    });

    let signals_handle = thread::spawn(move || {
        yield_signals(sender, stop_rx_signals);
    });

    // Main event loop
    for msg in receiver.iter() {
        match msg {
            Message::Key(c) => {
                println!\!"\rKey pressed: {}", c;
                if c == 'q' {
                    println!\!"\r'q' pressed. Initiating shutdown...";
                    break;
