  "main.rs": "//! This file demonstrates the solution to the design dilemma using `enum_dispatch`.
//!
//! Architecture:
//! 1. `al` (Abstract Layer): Defines the `Rest` trait annotated with `#[enum_dispatch]`.
//! 2. `il` (Implementation Layer): Defines `Foo` and `Boo` implementing `Rest`.
//! 3. `bl` (Business Layer): Defines the `Item` enum annotated with `#[enum_dispatch(Rest)]`.
//!
//! Key Solution:
//! The `enum_dispatch` macro allows the trait definition and the enum definition to reside
//! in different crates (modules here), provided the trait is annotated with the macro
//! in its definition crate (`al`). This enables static dispatch in `bl` without creating
//! a circular dependency between `al` and `il`.

// ------------------------------------------------------------------------------------------------
// Crate: al (Abstract Layer)
// ------------------------------------------------------------------------------------------------
mod al {
    use enum_dispatch::enum_dispatch;

    /// The trait is annotated here. This allows downstream crates (bl) to
    /// generate dispatch enums for this trait.
    #[enum_dispatch]
    pub trait Rest {
        fn get_id(&self) -> u32;
        fn process(&mut self, data: &str) -> String;
        // Imagine 18 other methods here...
    }
}

// ------------------------------------------------------------------------------------------------
// Crate: il (Implementation Layer)
// ------------------------------------------------------------------------------------------------
mod il {
    use crate::al::Rest;

    pub struct Foo {
        pub id: u32,
    }

    impl Rest for Foo {
        fn get_id(&self) -> u32 {
            self.id
        }

        fn process(&mut self, data: &str) -> String {
            format!("Foo({}) processing: {}", self.id, data)
        }
    }

    pub struct Boo {
        pub version: String,
    }

    impl Rest for Boo {
        fn get_id(&self) -> u32 {
            0 // Boo has a fixed ID
        }

        fn process(&mut self, data: &str) -> String {
            format!("Boo({}) processing: {}", self.version, data)
        }
    }
}

// ------------------------------------------------------------------------------------------------
// Crate: bl (Business Layer)
// ------------------------------------------------------------------------------------------------
mod bl {
    use crate::al::Rest;
    use crate::il::{Boo, Foo};
    use enum_dispatch::enum_dispatch;

    /// The enum dispatches the trait defined in `al`.
    /// This works across modules/crates because `Rest` was marked with `#[enum_dispatch]` in `al`.
    #[enum_dispatch(Rest)]
    pub enum Item {
        Foo(Foo),
        Boo(Boo),
    }
}

// ------------------------------------------------------------------------------------------------
// Main Execution
// ------------------------------------------------------------------------------------------------
use al::Rest;
use bl::Item;
use il::{Boo, Foo};

fn main() {
    // Create instances of the concrete types from `il`
    let f = Foo { id: 42 };
    let b = Boo { version: "v1.0".to_string() };

    // Wrap them in the `bl` enum
    let mut dispatcher_f = Item::Foo(f);
    let mut dispatcher_b = Item::Boo(b);

    // Use the trait methods directly on the enum (Static Dispatch)
    println!("ID of dispatcher_f: {}", dispatcher_f.get_id());
    println!("Processing with dispatcher_b: {}", dispatcher_b.process("hello world"));

    // Demonstrate mutating via the enum wrapper
    dispatcher_f.process("updated data");

    // Collect in a vector (no Box<dyn Rest> needed, fully monomorphized)
    let items: Vec<Item> = vec![dispatcher_f, dispatcher_b];

    println!("\nIterating over dispatched items:");
    for item in items {
        println!("Item ID: {}", item.get_id());
    }
}
"
}
