/// Loads the todo list from a file.
/// If the file does not exist or cannot be parsed, returns an empty vector.
fn load_or_create(path: &str) -> Vec<String> {
    let path = Path::new(path);

    // Check if the file exists
    if !path.exists() {
        return Vec::new();
    }

    // Attempt to read the file
    match fs::read_to_string(path) {
        Ok(content) => {
            // If file is empty, return empty vec
            if content.trim().is_empty() {
                return Vec::new();
            }

            // Attempt to parse JSON
            match serde_json::from_str(&content) {
                Ok(data) => data,
                Err(e) => {
                    eprintln!("Warning: Failed to parse JSON ({}). Starting with an empty list.", e);
                    Vec::new()
                }
            }
        }
        Err(e) => {
            eprintln!("Warning: Could not read file ({}). Starting with an empty list.", e);
            Vec::new()
        }
    }
}

/// Saves the todo list to a file, overwriting existing content.
/// This handles the "moving of the closing ]" by rewriting the structure.
fn save(path: &str, data: &Vec<String>) {
    // Convert the vector to a JSON string (Pretty printed for readability)
    let json = serde_json::to_string_pretty(data).expect("Failed to serialize data");

    // Write to file (creates the file if it doesn't exist, truncates if it does)
