fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0);

    let len = line_bytes.len();
    let steps = len / BYTES_PER_PIXEL / 2;
    let ptr = line_bytes.as_mut_ptr();

    for i in 0..steps {
        unsafe {
            // Calculate offsets for the left and right pixels to swap
            let left_offset = i * BYTES_PER_PIXEL;
            let right_offset = len - (i + 1) * BYTES_PER_PIXEL;

            // Cast pointers to *mut u32. 
            // We use read/write_unaligned because &[u8] alignment is 1,
            // and casting it to *mut u32 requires alignment of 4 to be valid.
            // Unaligned access is fast on modern AMD64 and ARM64 CPUs.
            let left_ptr = ptr.add(left_offset) as *mut u32;
            let right_ptr = ptr.add(right_offset) as *mut u32;

            let left_val = std::ptr::read_unaligned(left_ptr);
            let right_val = std::ptr::read_unaligned(right_ptr);

            std::ptr::write_unaligned(left_ptr, right_val);
            std::ptr::write_unaligned(right_ptr, left_val);
        }
    }
}

fn main() {
    // Run the test suite
    #[cfg(test)]
    run_tests();

    println!("Flip line benchmark/test executed successfully.");
}

#[cfg(test)]
fn run_tests() {
    const ORIGINAL_BYTES: [u8; BYTES_PER_PIXEL * PIXELS_PER_LINE] = [
        // 0
        1, 2, 3, 4, //
        // 1
        5, 6, 7, 8, //
        // 2
        9, 10, 11, 12, //
        // 3
        13, 14, 15, 16, //
        // --------------------
        // 4
        17, 18, 19, 20, //
        // 5
        21, 22, 23, 24, //
        // 6
        25, 26, 27, 28, //
        // 7
        29, 30, 31, 32,
    ];

    const TARGETED_BYTES: [u8; BYTES_PER_PIXEL * PIXELS_PER_LINE] = [
        // 7
        29, 30, 31, 32, //
        // 6
        25, 26, 27, 28, //
        // 5
        21, 22, 23, 24, //
        // 4
        17, 18, 19, 20, //
        // --------------------
        // 3
        13, 14, 15, 16, //
        // 2
        9, 10, 11, 12, //
        // 1
        5, 6, 7, 8, //
        // 0
        1, 2, 3, 4, //
    ];

    let mut mutated_bytes: [u8; 32] = ORIGINAL_BYTES;
    flip_line(&mut mutated_bytes);

    assert_eq!(mutated_bytes, TARGETED_BYTES, "The byte array was not flipped correctly");
}
