// Middleware to check the Origin header
async fn check_origin(
    req: Request,
    next: Next,
) -> Result<Response, StatusCode> {
    // Check if the Origin header exists and matches the allowed origin
    // Note: headers::Origin parses the header value for us
    let origin_header = req.headers().typed_get::<Origin>();

    match origin_header {
        Some(origin) => {
            // We compare the string representation. 
            // For stricter checks, you might want to parse and compare scheme/host/port separately.
            if origin.to_string() == ALLOWED_ORIGIN {
                Ok(next.run(req).await)
            } else {
                println!("Blocked request from origin: {}", origin);
                Err(StatusCode::FORBIDDEN)
            }
        }
        None => {
            // Websockets from browsers always send an Origin header. 
            // You might choose to allow requests without Origin (e.g. non-browser clients)
            // or block them. Here we block them.
            println!("Blocked request with missing Origin header");
            Err(StatusCode::FORBIDDEN)
        }
    }
}

// The actual websocket handler
async fn ws_handler(ws: WebSocketUpgrade) -> Response {
    // This is only reached if the middleware allows it
    ws.on_upgrade(handle_socket)
}

// Logic for the websocket stream
async fn handle_socket(mut socket: WebSocket) {
    while let Some(msg) = socket.recv().await {
        let msg = if let Ok(msg) = msg {
            msg
        } else {
            // client disconnected
            return;
        };

        if socket.send(msg).await.is_err() {
            // client disconnected
            return;
        }
    }
}
