/// Optimized blob processor
/// Uses `buffer_unordered` to maintain a constant concurrent flow of downloads,
/// mimicking the C# Parallel.ForEachAsync behavior.
async fn process_blobs_optimized(container_client: Arc<ContainerClient>, prefix: String) -> Vec<TradeData> {
    // 1. Create a stream of blob names
    // We use into_stream() to handle pagination of the list operation automatically
    let blob_list_stream = container_client
        .list_blobs()
        .prefix(prefix.clone())
        .into_stream()
        .then(|page_result| async move {
            match page_result {
                Ok(response) => response.blobs.blobs().to_vec(),
                Err(e) => {
                    eprintln!("Error listing blobs: {:?}", e);
