    // C# Parallel.ForEachAsync uses Environment.ProcessorCount by default.
    // We use num_cpus to match that behavior, preventing socket exhaustion or throttling.
    let concurrency_limit = num_cpus::get();

    // 3. Process the stream
    // We map the blob item to a future (download + parse) and buffer them.
    // This ensures we are always processing `concurrency_limit` items, effectively
    // pipelining the listing and downloading steps.
    let trades: Vec<TradeData> = blob_list_stream
        .map(move |blob| {
            let client = container_client.clone();
            async move {
                if !blob.name.ends_with(".json") {
                    return None;
                }

                let blob_client = client.blob_client(&blob.name);

                // Download
                match blob_client.get_content().await {
                    Ok(data) => {
                        // Parse
                        match serde_json::from_slice::<TradeData>(&data) {
                            Ok(trade) => Some(trade),
                            Err(e) => {
                                eprintln!("Failed to parse {}: {}", blob.name, e);
                                None
                            }
                        }
                    }
                    Err(e) => {
                        eprintln!("Failed to download {}: {}", blob.name, e);
                        None
                    }
                }
            }
        })
        .buffer_unordered(concurrency_limit) // The key optimization
        .filter_map(|x| async { x }) // Filter out Nones
        .collect()
        .await;

    trades
}"
