    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_word = false;
    let mut in_quotes = false;

    for ch in input.chars() {
        if in_quotes {
            if ch == '\'' {
                in_quotes = false;
            } else {
                current_token.push(ch);
            }
            // We are in a word as long as we are inside quotes
            in_word = true;
        } else {
            match ch {
                '\'' => {
                    in_quotes = true;
                    // Starting a quote starts a word (even if empty like '')
                    in_word = true;
                }
                // Using is_whitespace() to handle tabs/newlines like Bash does
                c if c.is_whitespace() => {
                    if in_word {
                        tokens.push(std::mem::take(&mut current_token));
                        in_word = false;
                    }
                }
                _ => {
                    current_token.push(ch);
                    in_word = true;
                }
            }
        }
    }

    // If the string ends while we are still in a word (or unclosed quote), save the token
    if in_word {
        tokens.push(current_token);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);

    // Output format matching the prompt's bash example
    println!("{} args:", tokens.len());
    for token in &tokens {
