// Simple Ray-AABB intersection returning the normal in local space
fn ray_aabb_intersection(ray_origin: Vec3, ray_direction: Vec3) -> Option<(f32, Vec3)> {
    let min = Vec3::splat(-0.5);
    let max = Vec3::splat(0.5);

    let mut t_min = 0.0;
    let mut t_max = f32::INFINITY;
    let mut normal = Vec3::ZERO;

    // Check intersection for each axis
    for i in 0..3 {
        let inv_d = 1.0 / ray_direction[i];
        let t1 = (min[i] - ray_origin[i]) * inv_d;
        let t2 = (max[i] - ray_origin[i]) * inv_d;

        let (t_near, t_far, n_near) = if t1 < t2 {
            (t1, t2, -Vec3::AXES[i])
        } else {
            (t2, t1, Vec3::AXES[i])
        };

        if t_near > t_min {
            t_min = t_near;
            normal = n_near;
        }
        t_max = t_max.min(t_far);
    }

    if t_min > t_max {
        return None;
    }

    // We only care about entry point (t_min > 0)
    if t_min > 0.0 {
        Some((t_min, normal))
    } else {
        None
    }
}
"
}
