use std::future::Future;
use std::sync::Arc;
use futures::future::BoxFuture;

// Minimal structs for illustration
#[derive(Debug)]
pub struct Request;
#[derive(Debug)]
pub struct Response;

// Unified stored type: (Request) -> BoxFuture<'static, Response>
// Note: We switch to owned `Request` to avoid the complex HRTB lifetime issues
// that occur when async closures capture arguments by reference across generic boundaries.
type HandlerFn = dyn Fn(Request) -> BoxFuture<'static, Response> + Send + Sync + 'static;

pub struct Handler(Arc<HandlerFn>);

// Trait to allow polymorphism over sync/async
pub trait IntoHandler {
    fn into_handler(self) -> Handler;
}

// Implementation for a `sync` handler: Fn(Request) -> Response
impl<F> IntoHandler for F
where
    F: Fn(Request) -> Response + Send + Sync + 'static,
{
    fn into_handler(self) -> Handler {
        Handler(Arc::new(move |req| Box::pin(async move { self(req) })))
    }
}

// Wrapper struct for async handlers.
// This is required to prevent overlapping implementations with the sync handler,
// as Rust does not support specialization on stable yet.
pub struct Async<F>(pub F);

// Implementation for an `async` handler wrapped in `Async`: Fn(Request) -> impl Future
impl<F, Fut> IntoHandler for Async<F>
where
    F: Fn(Request) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = Response> + Send + 'static,
{
    fn into_handler(self) -> Handler {
        Handler(Arc::new(move |req| Box::pin(self.0(req))))
    }
}

// Simplified server
pub struct Server {
    handlers: Vec<Handler>,
}

impl Server {
    pub fn new() -> Self {
        Self { handlers: vec![] }
    }

    // The single function accepting both kinds via IntoHandler
    pub fn add_route<H>(&mut self, _path: &str, handler: H)
    where
        H: IntoHandler,
    {
        let handler = handler.into_handler();
        self.handlers.push(handler);
        println!("Route added (handler stored).");
    }
}

// --- User Code ---

fn sync_handler(_req: Request) -> Response {
    println!("Sync handler processing...");
    Response
}

async fn async_handler(_req: Request) -> Response {
    println!("Async handler processing...");
    Response
}

#[tokio::main]
async fn main() {
    let mut server = Server::new();

    // The same call works for sync handlers
    server.add_route("/sync", sync_handler);

    // For async handlers, we wrap them in `Async` to distinguish them from sync functions.
    // This is the most ergonomic approach available on stable Rust without specialization.
    server.add_route("/async", Async(async_handler));

    // You can also pass closures
    server.add_route("/sync_closure", |req: Request| Response);
    server.add_route("/async_closure", Async(|req: Request| async move { Response }));

    println!("Server setup complete.");
}"
}
