fn split_zip_path(path: &PathBuf) -> Option<(PathBuf, String)> {
    let mut archive_path = PathBuf::new();
    let mut internal_parts = Vec::new();
    let mut found_archive = false;

    for component in path.components() {
        if let std::path::Component::Normal(os_str) = component {
            if !found_archive {
                archive_path.push(os_str);
                // Check if this component ends with .zip
                if os_str.to_string_lossy().ends_with(".zip") {
                    found_archive = true;
                }
            } else {
                internal_parts.push(os_str.to_string_lossy().into_owned());
            }
        }
    }

