const BYTES_PER_PIXEL: usize = 4;

/// Flip a single line.
/// Optimization: Manual unrolling and treating 4-byte pixels as u32s.
/// This reduces the operation count by a factor of 4 compared to byte-swapping.
/// The unrolling eliminates loop overhead (branching), which is beneficial
/// for small fixed-size data on embedded hardware.
/// 
/// Safety: We use `read_unaligned`/`write_unaligned` to handle potential 
/// alignment issues with `u8` slices, while still benefitting from 32-bit register operations.
fn flip_line(line_bytes: &mut [u8]) {
    const LEN: usize = PIXELS_PER_LINE * BYTES_PER_PIXEL;
    debug_assert_eq!(line_bytes.len(), LEN);

    // Cast the pointer to u32. This allows us to swap whole pixels at once.
    let ptr = line_bytes.as_mut_ptr() as *mut u32;

