    // It is thread-safe and ensures the connection logic runs only once.
    client: OnceCell<Client>,
}

// A wrapper to handle the difference between the cached client (borrowed)
// and temporarily created clients (owned).
pub enum ClientWrapper<'a> {
    Owned(Client),
    Borrowed(&'a Client),
}

impl Deref for ClientWrapper<'_> {
    type Target = Client;

    fn deref(&self) -> &Self::Target {
        match self {
