fn main() -> Result<()> {
    // 2. Determine the filesystem path:
    // Since the script is embedded, we must materialize it onto the filesystem 
    // so the `python` interpreter can access it by path.
    // We create a temporary file to serve as this path.
    let mut temp_script = tempfile::Builder::new()
        .suffix(".py")
        .tempfile()
        .context("Failed to create a temporary file for the python script")?;

    // Write the embedded content to the temp file
    temp_script.write_all(SCRIPT_CONTENT.as_bytes())
        .context("Failed to write python script content to temp file")?;

    // Get the path to pass to the Python interpreter
    let script_path = temp_script.path();

    // Ensure the path persists long enough for the interpreter to read it.
    // `into_temp_path()` converts the TempFile into a PathBuf that doesn't auto-delete on drop,
    // but we need to handle cleanup manually or just let the OS clean up /tmp.
    // For a robust CLI, we keep the handle (temp_script) so it deletes when main ends.
    // Note: We must flush/sync data to disk before passing to another process.
    temp_script.as_file_mut().sync_all()?;

    println!("Running embedded python script...");

    // 3. Invoke the Python interpreter
    // We try 'python3', falling back to 'python' if not found.
    let python_executable = if Command::new("python3").arg("--version").output().is_ok() {
        "python3"
    } else {
        "python"
