impl Agent {
    pub fn new() -> Result<Self> {
        // 1. Spawn the session (e.g., bash)
        // We use `new()` which spawns the default shell.
        let mut session = Session::new()?;

        // 2. Solution: Split the File Descriptor.
        // The `expectrl::Session` holds the Master PTY FD. 
        // Reading and Writing to the PTY usually happens on the same FD.
        // The deadlock occurs because we lock the whole Session to Read, preventing Writes.
        // 
        // Fix: Duplicate the FD using `dup`. 
        // We get two independent handles to the same PTY: one for reading, one for writing.
        // This allows us to drop the Mutex requirement for reading.

        let raw_fd = session.as_raw_fd();
        let writer_fd = dup(raw_fd)?;

        // Wrap the duplicated FD in a File handle for the writer side.
        // SAFETY: `dup` returns a valid raw fd. `from_raw_fd` consumes it into a File.
        let writer_handle = unsafe { std::fs::File::from_raw_fd(writer_fd) };
        let writer = Arc::new(Mutex::new(writer_handle));

        // 3. Spawn the Reader Thread
        // We move the `session` (the original owner of the FD) into the thread.
        // No Mutex is needed here because this thread has exclusive ownership of the reader side.
        let reader_writer_clone = writer.clone();
        thread::spawn(move || {
            let mut buf = [0u8; 1024];
            println!("[Backend] Reader thread started.");

            // We implement a loop that reads from the PTY.
            // Note: session.read() is blocking. 
            // Because we have no Mutex, the main thread can still write via `writer`.
            loop {
                match session.read(&mut buf) {
                    Ok(n) if n > 0 => {
                        let output = String::from_utf8_lossy(&buf[..n]);
                        // In Tauri, you would emit an event here:
                        // app.emit("agent-output", output.to_string());
                        print!("{}", output);
                        std::io::stdout().flush().unwrap();
