                        break;
                    }
                }
            }

            println!("[Backend] Reader thread finished.");
            // Cleanup logic if needed
        });

        Ok(Self { writer })
    }

    /// Sends data to the PTY. 
    /// This is called from the "UI" (main thread in this example).
    /// It will not block even if the reader thread is waiting for data.
    pub fn send(&mut self, data: &str) -> Result<()> {
        let mut guard = self.writer.lock().unwrap();
        // We write directly to the duplicated FD.
        guard.write_all(data.as_bytes())?;
        guard.flush()?;
