/// works even if the mouse leaves the specific element.
#[component]
fn DragProvider(children: Element) -> Element {
    // Initialize the global state
    let state = use_context_provider(|| DragState {
        active_id: Signal::new(None),
        mouse_pos: Signal::new((0.0, 0.0)),
    });

    rsx! {
        div {
            // We capture events on the container level
            onmousemove: move |evt| {
                // Update the global mouse position signal
                state.mouse_pos.set(evt.client_coordinates());

                // Note: We don't need to manually trigger callbacks here.
                // Components reading `mouse_pos` will re-render automatically.
            },
            onmouseup: move |_| {
                // Clear the active ID when mouse is released
                state.active_id.set(None);
            },
            // Optional: cancel drag if mouse leaves the window/container
            onmouseleave: move |_| {
                state.active_id.set(None);
            },

            {children}
        }
    }
}

/// A draggable point component.
/// It reads from the global DragState to update its position, 
/// demonstrating fine-grained reactivity (only the dragged component updates).
#[component]
fn Point(id: usize, start_x: f64, start_y: f64, color: String) -> Element {
    // Local state for the element's position
    let mut pos = use_signal(|| (start_x, start_y));
    // Local state to store the offset between the mouse click and the element's center
    // to prevent the element from "jumping" to the mouse cursor center.
    let mut drag_offset = use_signal(|| (0.0, 0.0));

    // Consume the global context
    let drag_state = use_context::<DragState>();

    // Check if THIS component is the one being dragged
    let is_dragging = *drag_state.active_id.read() == Some(id);

    // Determine the current visual position.
    // We rely on Dioxus's fine-grained reactivity:
    // 1. `is_dragging` reads `active_id`.
    // 2. If `true`, we read `mouse_pos`.
    // 3. If `false`, we only read local `pos`.
    // 
    // This means: 
    // - Moving the mouse updates `mouse_pos`.
    // - ONLY the component where `is_dragging` is true (and reading `mouse_pos`) will re-render.
    // - Other components do NOT re-render because they don't read `mouse_pos` inside the conditional.
    let (cx, cy) = if is_dragging {
        let (mx, my) = *drag_state.mouse_pos.read();

        // Calculate new position based on mouse + stored offset
        let new_x = mx - drag_offset.read().0;
        let new_y = my - drag_offset.read().1;

        // Persist the new position locally so it stays when we stop dragging
        pos.set((new_x, new_y));

        (new_x, new_y)
    } else {
        // Static position when not dragging
        *pos.read()
    };

    rsx! {
        circle {
            cx: cx,
            cy: cy,
            r: 20.0,
            fill: color.clone(),
