// futures crate provides a safe noop waker implementation
use futures::task::noop_waker;

#[derive(Debug)]
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Tries to poll a future synchronously.
/// 
/// Note: The future must implement `Unpin` to allow polling via a mutable reference.
/// Most futures returned by async blocks or functions are `Unpin`.
fn try_poll<X>(future: &mut impl Future<Output = X> + Unpin) -> TryPollResult<X> {
    // Create a "noop" waker. 
    // Since we are only doing a single check poll, we don't need a real waker 
    // to schedule a wake-up. If the future is Pending, it will rely on the 
    // executor (via the spawn) to provide a real waker later.
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    // Pin the future. Because we required Unpin, this is safe.
    let pinned = Pin::new(future);

    match pinned.poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    // --- Case 1: Future is Ready immediately ---
    println!("--- Case 1: Ready Future ---");
    let mut ready_future = async { 42 };

    // We can call try_poll in a non-async block (like this closure)
    let result = tokio::task::spawn_blocking(move || {
        try_poll(&mut ready_future)
    }).await.unwrap();

    match result {
        TryPollResult::Ready(val) => println!("Future was ready: {}", val),
        TryPollResult::Pending => println!("Future was pending (unexpected)"),
    }

    // --- Case 2: Future is Pending ---
    println!("\n--- Case 2: Pending Future ---");

    // We simulate a non-async context logic here using a standard thread,
    // but this logic works anywhere (like inside a synchronous callback).
    std::thread::spawn(move || {
        // Create a future that waits for 100ms. 
        // We use Box::pin to make it Unpin and satisfy the trait bounds easily.
        let mut pending_future = Box::pin(tokio::time::sleep(std::time::Duration::from_millis(100)));

        println!("Polling the future synchronously...");
        match try_poll(&mut pending_future) {
            TryPollResult::Ready(_) => {
                println!("Future completed immediately."); 
            },
            TryPollResult::Pending => {
                println!("Future is pending. Spawning a Tokio task to await it...");

                // We can spawn a task on the Tokio runtime from this thread
                // because we used a multi-threaded runtime ("full" features).
                // We take ownership of the future here.
                tokio::runtime::Handle::current().spawn(async move {
                    pending_future.await;
                    println!("Future completed inside the spawned task!");
                });
            }
        }
    }).join().unwrap();

    // Wait long enough for the spawned task to finish
    tokio::time::sleep(std::time::Duration::from_millis(500)).await;
    println!("Done.");
}
