// This struct acts as our "Event Bus" for custom events.
// We use Rc<RefCell<...>> to allow the callback to be updated dynamically
// without triggering a re-render of the component tree when the listener changes.
#[derive(Clone, Default)]
pub struct DragController {
    // The callback accepts the mouse coordinates (x, y) relative to the container
    active_dragger: Rc<RefCell<Option<Rc<dyn Fn(i32, i32)>>>>,
}

impl DragController {
    pub fn set_listener(&self, callback: Option<Rc<dyn Fn(i32, i32)>>) {
        *self.active_dragger.borrow_mut() = callback;
    }

    pub fn trigger_move(&self, x: i32, y: i32) {
        if let Some(cb) = self.active_dragger.borrow().as_ref() {
            cb(x, y);
        }
    }
