fn Point(x: i32, y: i32) -> Element {
    // Signal to hold the current position
    let mut pos = use_signal(|| (x, y));
    // Signal to hold the offset from the click point to the top-left of the element
    // (simulating grabbing the point at the click location)
    let mut drag_offset = use_signal(|| (0, 0));

