fn is_input_incomplete(input: &str) -> bool {
    let trimmed = input.trim_end();

    // 1. Explicit continuation with backslash
    if trimmed.ends_with('\\') {
        return true;
    }

    // 2. Check for unbalanced braces/parentheses
    let mut brace_level = 0;
    let mut paren_level = 0;

    for c in trimmed.chars() {
        match c {
            '{' => brace_level += 1,
            '}' => brace_level -= 1,
            '(' => paren_level += 1,
            ')' => paren_level -= 1,
            _ => (),
        }
    }

    if brace_level > 0 || paren_level > 0 {
