// Simple OBB Raycast implementation for a unit cube
fn raycast_cube(ray: Ray, transform: &Transform) -> Option<(Vec3, Vec3)> {
    // Transform ray into the cube's local space
    let inv_rotation = transform.rotation.inverse();
    let local_origin = inv_rotation * (ray.origin - transform.translation);
    let local_direction = inv_rotation * ray.direction;

    // Unit cube bounds
    let min = Vec3::splat(-0.5);
    let max = Vec3::splat(0.5);

    let mut t_enter = f32::NEG_INFINITY;
    let mut t_exit = f32::INFINITY;
    let mut normal_enter = Vec3::ZERO;

    // Slab method for AABB intersection
    for i in 0..3 {
        let origin = local_origin[i];
        let direction = local_direction[i];
        let b_min = min[i];
        let b_max = max[i];

        if direction.abs() < 1e-6 {
            // Ray is parallel to slab
            if origin < b_min || origin > b_max {
                return None;
            }
        } else {
            // Calculate intersection t values
            let t1 = (b_min - origin) / direction;
            let t2 = (b_max - origin) / direction;

            // Prepare normal for this axis
            let mut n1 = Vec3::ZERO;
            n1[i] = -1.0;
            let mut n2 = Vec3::ZERO;
            n2[i] = 1.0;

            // Ensure t1 is near, t2 is far
            let (t_near, t_far, n_near) = if t1 < t2 {
                (t1, t2, n1)
            } else {
                (t2, t1, n2)
            };

            // Update global entry/exit
            if t_near > t_enter {
                t_enter = t_near;
                normal_enter = n_near;
            }
            t_exit = t_exit.min(t_far);
        }
    }

    // Check for valid intersection
    if t_enter > t_exit || t_exit < 0.0 {
        return None;
    }

    // Use t_enter if we are outside the box, t_exit if we are inside
    let t_hit = if t_enter >= 0.0 { t_enter } else { t_exit };

    // Calculate hit position in local space, then transform to world
    let local_hit = local_origin + local_direction * t_hit;
    let world_hit = transform.rotation * local_hit + transform.translation;
    let world_normal = transform.rotation * normal_enter; // Transform local normal to world

    Some((world_hit, world_normal))
}
