// --- 3. Implement for Option ---
// This is where the 'wildcard' logic happens. 
// If the filter is None, it matches anything (wildcard).
// If the filter is Some, the target must be Some and the inner values must match.
impl<T: FilterMatch> FilterMatch for Option<T> {
    fn matches(&self, filter: &Self) -> bool {
        match filter {
            None => true, // No filter constraint, so it matches
            Some(filter_val) => {
                match self {
                    None => false, // Filter requires a value, but target has none
                    Some(self_val) => self_val.matches(filter_val), // Recursive call
                }
            }
        }
    }
