    const fn new(seed: u64) -> Self {
        Self {
            state: if seed == 0 { 1 } else { seed },
        }
    }

    /// Generates the next u64 in the sequence.
    const fn next_u64(&mut self) -> u64 {
        // XorShift64 algorithm
        let mut x = self.state;
        x ^= x << 13;
        x ^= x >> 7;
        x ^= x << 17;
        self.state = x;
        x
    }
}

pub static ZOBRIST_SEEDS: [u64; 781] = generate_zobrist_seeds();

/// Generates the Zobrist seeds at compile time.
const fn generate_zobrist_seeds() -> [u64; 781] {
    let mut result = [0; 781];
    // Initialize the PRNG with the desired seed
    let mut rng = ConstPrng::new(4174800045971885562);

    // Standard 'while' loops are allowed in const fns in modern Rust
    let mut i = 0;
    while i < 781 {
        result[i] = rng.next_u64();
        i += 1;
    }
    result
}

fn main() {
    // Verify that the seeds were generated at compile time by printing a few.
    // Since ZOBRIST_SEEDS is a static, it is initialized during compilation.
    println!("First 5 Zobrist seeds:");
    for i in 0..5 {
        println!("  Index {}: {}", i, ZOBRIST_SEEDS[i]);
    }

    println!("\nLast seed:");
    println!("  Index 780: {}", ZOBRIST_SEEDS[780]);

    // Check memory location to prove it's a static
    println!("\nStatic array address: {:p}", &ZOBRIST_SEEDS);
}
"
