// ----------------------------------------------------------------------------
// 1. The Custom Asset Reader
// ----------------------------------------------------------------------------

/// A custom AssetReader that treats `.zip` files as directories.
/// This enables "lazy" loading because we only read the specific file requested 
/// inside the zip, rather than loading the whole zip into memory upfront.
struct ZipAssetReader {
    root_path: std::path::PathBuf,
}

impl ZipAssetReader {
    pub fn new(root_path: std::path::PathBuf) -> Self {
        Self { root_path }
    }
}

impl AssetReader for ZipAssetReader {
    fn read<'a>(
        &'a self,
        path: &'a Path,
    ) -> Pin<Box<dyn ConditionalSendFuture<Output = Result<Box<Reader<'a>>, AssetReaderError>> + 'a>>
    {
        Box::pin(async move {
            // We expect paths like: "archive.zip/texture.png"
            // We need to split this into the zip file path and the internal file path.
            let path_str = path.to_string_lossy();

            // Find the ".zip" part to split the path
            if let Some(split_idx) = path_str.find(".zip") {
                let end_idx = split_idx + 4; // include ".zip"
                let zip_path = self.root_path.join(&path_str[..end_idx]);
                let internal_path = &path_str[end_idx + 1..]; // skip the '/' after .zip

                // 1. Open the zip file from disk
                // We use std::fs::File for the zip crate, which is blocking. 
                // In a production app, consider using tokio::fs in a blocking task.
                let file = std::fs::File::open(&zip_path)
                    .map_err(|e| AssetReaderError::Io(e.into()))?;

                // 2. Parse the zip archive
                let mut archive = zip::ZipArchive::new(file)
                    .map_err(|e| AssetReaderError::Io(std::io::Error::new(std::io::ErrorKind::InvalidData, e)))?;

                // 3. Find the specific file within the zip
                let mut zip_file = archive.by_name(internal_path)
                    .map_err(|_| AssetReaderError::NotFound(path.to_path_buf()))?;

                // 4. Read the file contents into a buffer
                let mut buffer = Vec::new();
                zip_file.read_to_end(&mut buffer)
                    .map_err(|e| AssetReaderError::Io(e))?;

                // 5. Return a Cursor over the buffer wrapped in Bevy's Reader
                Ok(Box::new(Cursor::new(buffer)))
            } else {
                // If it's not a zip path, fallback to standard file reading (optional, or error)
                Err(AssetReaderError::NotFound(path.to_path_buf()))
            }
        })
    }

    fn read_meta<'a>(
        &'a self,
        path: &'a Path,
    ) -> Pin<Box<dyn ConditionalSendFuture<Output = Result<Box<Reader<'a>>, AssetReaderError>> + 'a>>
    {
        // For this demo, we simply claim there is no metadata.
        // Bevy will fallback to default asset settings.
        Box::pin(async move { Err(AssetReaderError::NotFound(path.to_path_buf())) })
    }

    fn read_directory<'a>(
        &'a self,
        _path: &'a Path,
    ) -> Pin<Box<dyn ConditionalSendFuture<Output = Result<Box<dyn Iterator<Item = PathBuf> + Send>, AssetReaderError>> + 'a>>
    {
        // Implementing directory listing for zip contents is complex and out of scope
        // for a minimal demo, but would be needed for asset discovery.
        Box::pin(async move { Err(AssetReaderError::Io(std::io::Error::new(std::io::ErrorKind::Unsupported, "Not implemented"))) })
    }

    fn is_directory<'a>(
        &'a self,
        _path: &'a Path,
    ) -> Pin<Box<dyn ConditionalSendFuture<Output = bool> + 'a>> {
        Box::pin(async move { false })
    }
}

// ----------------------------------------------------------------------------
// 2. Main Setup
// ----------------------------------------------------------------------------

fn main() {
    // Setup the assets folder path (simulating getting the path)
    let assets_dir = std::env::current_dir().unwrap().join("assets");

    // Create a dummy zip file for the demo
    create_dummy_zip(&assets_dir);

    App::new()
        // We need to manually insert the AssetServer with our custom reader
        // because `add_asset_source` isn't exposed easily on the default plugins.
        // Instead, we can override the default asset reader.
        .insert_resource(bevy::asset::io::AssetSource::new(
            ZipAssetReader::new(assets_dir.clone()),
