// This effectively 'erases' the specific type of the future returned by the async function,
// allowing us to name the type in the function signature.
// The `+ Send` bound is typical for async runtimes like Tokio.
type BoxedFuture<'a, T> = Pin<Box<dyn Future<Output = T> + Send + 'a>>;

// The `harness` function now expects a closure that returns a BoxedFuture.
// The `for<'a>` syntax (Higher-Ranked Trait Bound) indicates that the closure
// must work for any lifetime 'a. This solves the "one lifetime is more general than the other" error
// because the return type is no longer a specific opaque type tied to one lifetime, 
// but a trait object that can handle any lifetime.
async fn harness<F>(test: F)
where
    F: for<'a> Fn(&'a mut String) -> BoxedFuture<'a, ()>,
{
    let mut string = String::new();
    test(&mut string).await;
    println!("new string is:\n{string}");
}

async fn simple_test(string: &mut String) {
    string.push_str("test result\n");
}

#[tokio::main]
async fn main() {
    // We pass a closure that wraps the async function call in `Box::pin`.
    // This converts the specific anonymous future returned by `simple_test` 
    // into the `BoxedFuture` trait object expected by `harness`.
    harness(|s: &mut String| Box::pin(simple_test(s))).await;
}
