  "main.rs": "/// Tokenizes a shell command string into a vector of arguments,
/// respecting single quotes for grouping and preserving inner spaces.
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();

    // We use a simple state machine to track whether we are inside a quoted string.
    #[derive(Debug, Clone, Copy, PartialEq)]
    enum State {
        Whitespace, // Outside a token
        InToken,    // Inside an unquoted token
        InQuote,    // Inside a single-quoted token
    }

    let mut state = State::Whitespace;

    for c in input.chars() {
        match state {
            State::Whitespace => match c {
                '\'' => {
                    // Start a quoted section. 
                    // We don't push the quote itself.
                    state = State::InQuote;
                }
                ' ' => {
                    // Stay in whitespace
                }
                _ => {
                    // Start a new unquoted token
                    current_token.push(c);
                    state = State::InToken;
                }
            },
            State::InToken => match c {
                '\'' => {
                    // Enter a quoted section inside an ongoing token (gluing)
                    state = State::InQuote;
                }
                ' ' => {
                    // End of token
                    tokens.push(std::mem::take(&mut current_token));
                    state = State::Whitespace;
                }
                _ => {
                    current_token.push(c);
                }
            },
            State::InQuote => match c {
                '\'' => {
                    // End of quoted section. 
                    // We transition to InToken because the quoted part might be 
                    // immediately followed by unquoted characters (e.g., 'foo'bar).
                    state = State::InToken;
                }
                _ => {
                    current_token.push(c);
                }
            },
        }
    }

    // Handle the final token if the string didn't end with whitespace
    if state != State::Whitespace {
        tokens.push(current_token);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let args = tokenize(input);

    println!("{} args:", args.len());
    for arg in &args {
        println!("<{}>", arg);
    }
}"
