#[inline(never)]
pub fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len(), LINE_SIZE_BYTES);

    // We explicitly handle the most common architectures for Raspberry Pi (AArch64)
    // and standard Desktop (x86_64).
