    {
        // Interpret bytes as u32 array for faster swapping (one instruction vs 4 swaps)
        // Safety: We ensure size is exact multiple and alignment is handled by copy.
        // Ideally `align_to_mut` is used, but for a simple 32-byte stack array,
        // the compiler optimizes a standard loop well.
        let ptr = line_bytes.as_mut_ptr() as *mut u32;
        let len = line_bytes.len() / 4;

