#[target_feature(enable = "sse2")]
unsafe fn flip_line_x86_64(ptr: *mut u8) {
    use arch::x86_64::*;

    // Load the 32-byte line as two 128-bit vectors.
    // Line layout: [Pixel0, P1, P2, P3] [P4, P5, P6, P7]
    let lo = _mm_loadu_si128(ptr as *const __m128i);
    let hi = _mm_loadu_si128(ptr.add(16) as *const __m128i);

    // Reverse the 32-bit integers within each vector.
    // _MM_SHUFFLE(0, 1, 2, 3) reverses the order.
    // [P0, P1, P2, P3] becomes [P3, P2, P1, P0]
    let mask = _MM_SHUFFLE(0, 1, 2, 3);
    let lo_rev = _mm_shuffle_epi32(lo, mask);
    let hi_rev = _mm_shuffle_epi32(hi, mask);

    // Store the swapped halves.
    // The reversed High part goes to the Low address.
    // The reversed Low part goes to the High address.
    _mm_storeu_si128(ptr as *mut __m128i, hi_rev);
    _mm_storeu_si128(ptr.add(16) as *mut __m128i, lo_rev);
}

