    let lo = vld1q_u32(ptr as *const u32);
    let hi = vld1q_u32(ptr.add(16) as *const u32);

    // Reverse elements in each vector.
    // `vrev64q_u32` reverses 32-bit elements within 64-bit lanes: [A, B, C, D] -> [B, A, D, C].
    // This is not a full vector reverse. 
    // To reverse fully [0, 1, 2, 3] -> [3, 2, 1, 0]:
    // 1. Swap the 64-bit halves (vextq_u32).
    // 2. Reverse within 64-bit lanes (vrev64q_u32).
    // OR combine differently.

    // Let's do the specific efficient AArch64 sequence:
    // rev64 reverses elements in 64-bit halves. [0, 1, 2, 3] -> [1, 0, 3, 2]
    // combine with swap.
    // 
    // Alternative:
    // Load as u32x4.
    // lo = [0, 1, 2, 3]
    // hi = [4, 5, 6, 7]
    // We want lo_result = [7, 6, 5, 4] and hi_result = [3, 2, 1, 0]

    // 1. Reverse 64-bit pairs:
    // lo_ext = [2, 3, 0, 1]
    // hi_ext = [6, 7, 4, 5]
    let lo_ext = vextq_u32(lo, lo, 2);
    let hi_ext = vextq_u32(hi, hi, 2);

    // 2. Reverse elements within 64-bit lanes:
    // [2, 3, 0, 1] -> [3, 2, 1, 0]  (This matches our desired hi_result)
    // [6, 7, 4, 5] -> [7, 6, 5, 4]  (This matches our desired lo_result)
    let final_hi = vrev64q_u32(lo_ext);
    let final_lo = vrev64q_u32(hi_ext);

    vst1q_u32(ptr as *mut u32, final_lo);
    vst1q_u32(ptr.add(16) as *mut u32, final_hi);
