                // 1. Create the inner Series for the struct fields
                let s_c1 = Series::new(PlSmallStr::from("c1"), c1_vec);
                let s_c2 = Series::new(PlSmallStr::from("c2"), c2_vec);

                // 2. Create the StructChunked from the field series
                let struct_ca = StructChunked::from_series(
                    PlSmallStr::from("item"),
                    s_c1.len(),
                    [&s_c1, &s_c2].into_iter(),
                )?;

                // 3. Construct the ListArray using Arrow internals
                // We need to access the re-exported Arrow types from Polars
                use polars::export::arrow::array::ListArray;
                use polars::export::arrow::buffer::Buffer;
                use polars::export::arrow::datatypes::{DataType as ArrowDataType, Field as ArrowField};

                let inner_arr = struct_ca.chunks()[0].clone();

                // Define the Arrow DataType for the List (LargeList)
                let inner_field = ArrowField::new("item".into(), struct_ca.data_type().to_arrow(), false);
                let list_dt = ArrowDataType::LargeList(Box::new(inner_field));

                let list_arr = ListArray::new(
                    list_dt,
                    Buffer::from(offsets),
                    inner_arr,
                    None, // Validity buffer (None means no nulls at the list level)
                );

                // 4. Wrap the ListArray back into a Polars ListChunked
                let list_ca = unsafe {
                    ListChunked::from_chunks(PlSmallStr::from("result"), vec![Arc::new(list_arr)])
                };

                Ok(list_ca.into_column())
            },
            |_, f| {
                // Output type signature: List(Struct(c1: String, c2: String))
                Ok(Field::new(
                    f.name().clone(),
                    DataType::List(Box::new(DataType::Struct(vec![
                        Field::new(PlSmallStr::from("c1"), DataType::String),
                        Field::new(PlSmallStr::from("c2"), DataType::String),
                    ]))),
                ))
            },
        ),
    );

    // Collect and print the result
    let result = lf.collect()?;
    println!("{:?}", result);

    Ok(())
}
"
