  "main.rs": "//! Solution for the design dilemma using the `ambassador` crate.
//!
//! Architecture:
//! - `al` (Abstract Layer): Defines the `Rest` trait. In order to support
//!   static dispatch across crates without cyclic dependencies, we annotate
//!   the trait with `#[delegatable_trait]`.
//! - `il` (Implementation Layer): Defines `Foo` and `Boo` implementing `Rest`.
//!   It depends only on `al`.
//! - `bl` (Business Layer): Defines the `Item` enum. It depends on `al` and `il`.
//!   We use `#[derive(Delegate)]` and `#[delegate(Rest)]` to implement `Rest`
//!   for the enum, achieving static dispatch without requiring the enum to be
//!   in the same crate as the trait.

mod al {
    use ambassador::delegatable_trait;

    /// The `Rest` trait is defined in the Abstract Layer.
    /// `#[delegatable_trait]` enables other crates to implement this trait
    /// for their enums/structs via the ambassador macro.
    #[delegatable_trait]
    pub trait Rest {
        fn get(&self) -> u32;
        fn post(&self, data: u32);
    }
}

mod il {
    use crate::al::Rest;

    /// Implementation Layer: Foo
    pub struct Foo {
        pub id: u32,
    }

    impl Rest for Foo {
        fn get(&self) -> u32 {
            println!("Foo::get called");
            self.id
        }

        fn post(&self, data: u32) {
            println!("Foo::post called with {}", data);
        }
    }

    /// Implementation Layer: Boo
    pub struct Boo {
        pub val: u32,
    }

    impl Rest for Boo {
        fn get(&self) -> u32 {
            println!("Boo::get called");
            self.val * 2
        }

        fn post(&self, data: u32) {
            println!("Boo::post called with {}", data);
        }
    }
}

mod bl {
    use ambassador::Delegate;
    use crate::al::Rest;
    use crate::il::{Foo, Boo};

    /// Business Layer: The dispatching enum.
    /// 
    /// We derive `Delegate` and specify `Rest`. The `ambassador` macro
    /// generates the `impl Rest for Item` block automatically, delegating
    /// calls to the inner variants. This works even though `Rest` is defined
    /// in `al` and `Item` is defined here in `bl`.
    #[derive(Delegate)]
    #[delegate(Rest)]
    pub enum Item {
        Foo(Foo),
        Boo(Boo),
    }
}

fn main() {
    // Use the structures from the implementation layer
    let foo = il::Foo { id: 10 };
    let boo = il::Boo { val: 20 };

    // Wrap them in the business layer enum
    let item1 = bl::Item::Foo(foo);
    let item2 = bl::Item::Boo(boo);

    // Use trait methods directly on the enum (Static Dispatch)
    // No `dyn` is used here, the compiler knows exactly which method to call.
    println!("Running static dispatch tests:");

    let val1 = item1.get();
    println!("Result 1: {}", val1);

    let val2 = item2.get();
    println!("Result 2: {}", val2);
}
