  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};

// The result enum requested
#[derive(Debug)]
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

// A dummy waker that does nothing. 
// We use this because we only need to extract the value if it's immediately ready.
// If it's pending, we will spawn the future onto the tokio runtime, 
// where it will get a real waker.
fn create_noop_waker() -> Waker {
    const VTABLE: RawWakerVTable = RawWakerVTable::new(
        |_| RawWaker::new(std::ptr::null(), &VTABLE), // clone
        |_| {},                                       // wake
        |_| {},                                       // wake_by_ref
        |_| {},                                       // drop
    );
    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

/// Tries to poll a future synchronously.
/// 
/// Note: We take ownership of the future because `tokio::spawn` requires 
/// the future to be owned (to be 'static). If the future is pending, 
/// we must move it into the spawned task.
fn try_poll<F>(future: F) -> TryPollResult<F::Output>
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    // Create a context with our no-op waker
    let waker = create_noop_waker();
    let mut cx = Context::from_waker(&waker);

    // We must pin the future to poll it. 
    // We use Box::pin to put it on the heap. This allows us to move the 
    // pinned future into the tokio::spawn task later if it returns Pending.
    let mut future = Box::pin(future);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(result) => TryPollResult::Ready(result),
        Poll::Pending => {
            // The future is not ready. Spawn it on the tokio runtime.
            // We can safely move the Box<dyn Future ...> into the spawn.
            tokio::spawn(async move {
                let result = future.await;
                println!("Spawned task completed with result: {:?}", result);
            });
            TryPollResult::Pending
        }
    }
}

// Example usage
fn main() {
    // We need a tokio runtime context to spawn tasks
    let rt = tokio::runtime::Runtime::new().unwrap();

    rt.block_on(async {
        println!("--- Test 1: Immediate value ---");
        let future1 = async { 42 };

        // Calling from a non-async function (simulated here, but works in regular functions too)
        match try_poll(future1) {
            TryPollResult::Ready(val) => println!("Immediately ready: {}", val),
            TryPollResult::Pending => println!("Pending"),
        }

        println!("\n--- Test 2: Delayed value ---");
        let future2 = async {
            // This causes the future to yield and return Pending initially
            tokio::time::sleep(std::time::Duration::from_millis(10)).await;
            100
        };

        match try_poll(future2) {
            TryPollResult::Ready(val) => println!("Immediately ready: {}", val),
            TryPollResult::Pending => println!("Pending (spawned task)", ),
        }

        // Wait a bit to ensure the spawned task finishes and prints its output
        tokio::time::sleep(std::time::Duration::from_millis(50)).await;
        println!("Done.");
    });
}
"
}
