fn main() {
    App::new()
        // Register our custom asset source named "archive"
        // This allows us to use paths like "archive://path/to/zip.zip/image.png"
        .register_asset_source(
            AssetSourceId::Name("archive".into()),
            AssetSource::build().with_reader(|| Box::new(ZipAssetReader)),
        )
        .add_plugins(DefaultPlugins)
        .add_systems(Startup, setup)
        .add_systems(Update, check_asset)
        .run();
