/// A custom AssetReader that treats .zip files as directories.
/// It enables lazy loading of individual files from within the zip
/// without extracting the whole archive.
struct ZipAssetReader;

impl AssetReader for ZipAssetReader {
    fn read<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Box<Reader<'a>>, AssetReaderError>> {
        Box::pin(async move {
            // 1. Parse the path.
            // Expected format: path/to/archive.zip/internal_file.ext
            let path_str = path.to_string_lossy();

            // We need to find the split between the zip file and the internal file.
            // We look for the first occurrence of ".zip/".
            if let Some(split_idx) = path_str.find(".zip/") {
                let archive_path_str = &path_str[..=split_idx + 3]; // include ".zip"
                let internal_path = &path_str[split_idx + 5..]; // skip ".zip/"

                // The AssetSource is rooted at the project folder (or assets folder depending on config).
                // We assume the zip is in the standard assets folder.
                let full_archive_path = Path::new("assets").join(archive_path_str);

                // 2. Open the Zip File.
                // Note: This approach opens the file and reads the central directory every time.
                // For production, you'd want to cache the ZipArchive index.
                let file = File::open(&full_archive_path)
                    .map_err(|_| AssetReaderError::NotFound(full_archive_path.clone()))?;

                let mut archive = ZipArchive::new(file)
                    .map_err(|e| AssetReaderError::Io(e.into()))?;

                // 3. Find the specific file within the zip.
                let mut zip_file = archive
                    .by_name(internal_path)
                    .map_err(|_| AssetReaderError::NotFound(path.to_path_buf()))?;

                // 4. Read the file contents into memory.
                // Since ZipFile is synchronous and requires the archive to live,
                // we read the bytes into a buffer to return an async reader.
                let mut bytes = Vec::new();
                zip_file.read_to_end(&mut bytes)
                    .map_err(|e| AssetReaderError::Io(e.into()))?;

                // 5. Return a Reader (AsyncRead).
                // Cursor<Vec<u8>> implements AsyncRead via futures-lite.
                Ok(Box::new(Cursor::new(bytes)))
            } else {
                Err(AssetReaderError::NotFound(path.to_path_buf()))
            }
        })
    }

    fn read_meta<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Box<Reader<'a>>, AssetReaderError>> {
        // We don't support .meta files inside zips for this example.
        Box::pin(async move { Err(AssetReaderError::NotFound(path.to_path_buf())) })
    }

    fn read_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Vec<PathBuf>, AssetReaderError>> {
        // Directory listing is complex for lazy loading without an index cache.
        Box::pin(async move { Err(AssetReaderError::NotFound(path.to_path_buf())) })
    }

    fn is_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<bool, AssetReaderError>> {
        // Simple check: if it ends with .zip, it's a file (archive), not a directory Bevy needs to traverse directly.
        Box::pin(async move { Ok(false) })
    }
}

// --- System to generate a dummy zip file and load it ---

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    // 1. Create a dummy zip file in assets/ so the example runs out of the box.
    // In a real project, you would already have this file.
