        let file = File::create(zip_path).expect("Could not create zip");
        let mut zip = zip::ZipWriter::new(file);

        // Generate a simple red image
        let img = image::ImageBuffer::from_pixel(64, 64, image::Rgba([255, 0, 0, 255]));
        let mut img_bytes: Vec<u8> = Vec::new();
