                    [r as u8, g as u8, b as u8]
                })
            })
            .collect();

        let data_len = pixels.len();

        // --- 4. Create Shared Memory Object ---
        // We use a unique name based on PID and frame count.
        let shm_name_str = format!("/kitty_anim_{}_{}", std::process::id(), frame_count);
        let shm_name = CString::new(shm_name_str.as_str()).unwrap();

        let fd = unsafe {
            libc::shm_open(
                shm_name.as_ptr(),
                libc::O_CREAT | libc::O_RDWR,
                0o666,
            )
        };

        if fd < 0 {
            eprintln!("Failed to create shared memory object");
            std::process::exit(1);
        }

        // Set the size of the shared memory object
        if unsafe { libc::ftruncate(fd, data_len as i64) } != 0 {
            eprintln!("Failed to set size of shared memory");
            unsafe { libc::close(fd); };
            std::process::exit(1);
        }

        // Map the shared memory into our address space
        let map_ptr = unsafe {
            libc::mmap(
                ptr::null_mut(),
                data_len,
                libc::PROT_WRITE,
                libc::MAP_SHARED,
                fd,
                0,
            )
        };

        if map_ptr == libc::MAP_FAILED {
            eprintln!("Failed to mmap shared memory");
            unsafe { libc::close(fd); };
            std::process::exit(1);
        }

        // --- 5. Copy data to shared memory ---
        unsafe {
            ptr::copy_nonoverlapping(pixels.as_ptr(), map_ptr as *mut u8, data_len);
            libc::munmap(map_ptr, data_len);
        }

        // --- 6. Send Kitty Graphics Protocol Command ---
        // Move cursor to home position
        write!(handle, "\x1b[H").unwrap();

        // t=s: transmission type=shared memory
        // S=<size>: size of data
        // H=<name>: name of shared memory object
        // a=T: action=transmit and display
        // d=A: delete all previous images (avoids memory leaks)
        // f=24: format=RGB (24-bit)
        // s=<w>,v=<h>: dimensions
        write!(
