// This is necessary because the Future returned by `simple_test` captures the 
// lifetime of the reference `&mut String`. 
//
// Rust's generic `Fut` type implies a single specific type, but a Future 
// borrowing an argument changes its type based on that argument's lifetime.
// Returning a `Pin<Box<dyn Future...>>` (Trait Object) erases the specific 
// lifetime details, allowing the harness to accept the function.
async fn harness<F>(test: F)
where
    // The closure takes a mutable reference to String.
    // It returns a Pin<Box> containing a Future that lives as long as the reference ('_).
    F: Fn(&mut String) -> Pin<Box<dyn Future<Output = ()> + '_>>,
{
    let mut string = String::new();
    string.push_str("Start of harness\n");

    // Call the closure, which boxes the future, and then await it.
    test(&mut string).await;

    println!("new string is:\n{string}");
}

#[tokio::main]
async fn main() {
    // We wrap `simple_test` in a closure that explicitly boxes the returned future.
    // This satisfies the `Fn(...) -> Pin<Box<...>>` signature of `harness`.
    harness(|s: &mut String| Box::pin(simple_test(s))).await;
}
