pub struct Context(i32);

// We switch from `dyn Fn` to `dyn FnOnce` to allow the closure
// to consume captured variables (one-shot execution).
// This requires changing the inner structure slightly to support `FnOnce`.
pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> FnOnce(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send,
        >,
    },
