// This helper wraps the provided async block into the necessary
// `Box<dyn FnOnce ...>` structure.
// 
// Note: On stable Rust, we cannot easily abstract over `FnOnce -> impl Future`
// where the future borrows from the arguments (HKT issues). 
// The standard workaround is to ask the caller to return a `Pin<Box<...>>`
// which allows erasing the return type while preserving the lifetime relationship.
pub fn with_context_async(
    work_sender: &Sender<InnerAsyncEvent>,
    block: impl for<'a> FnOnce(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
        + Send
        + 'static,
) {
    let event = InnerAsyncEvent::DoWithContext {
        block: Box::new(block),
    };
    let _ = work_sender.send(event);
}

