async fn main() {
    let (tx, mut rx) = channel(32);

    // Spawn the consumer task
    tokio::spawn(async move {
        let mut ctx = Context(0);
        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    block(&mut ctx).await;
                }
            }
        }
    });

    // Example 1: Simple usage
    with_context_async(&tx, |ctx| {
        Box::pin(async move {
            ctx.0 += 1;
            println!("Context value is now: {}", ctx.0);
        })
    });

    // Example 2: Capturing variables
    let increment = 10;
    with_context_async(&tx, move |ctx| {
        // We must use `move` here to capture `increment`
        // The `Box::pin` bundles the async block for the trait object
        Box::pin(async move {
            ctx.0 += increment;
            println!("Context value added {} -> {}", increment, ctx.0);
        })
    });

    // Wait a moment for processing
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
}
