    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];

        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Main entry point for building neighbor lists.
    /// 1. Clears existing lists.
    /// 2. Performs a divide-and-conquer traversal to compare elements.
    /// 3. Updates both elements symmetrically without unsafe code.
    pub fn build_lists(&mut self) {
        // Clear existing lists in parallel
        self.elems.par_iter_mut().for_each(|elem| elem.nb.clear());

        let cutoff = self.cutoff;

        // Start the recursive processing
        self.process_batch(&mut self.elems, 0, cutoff);
    }

    /// Recursive function to process a batch of elements.
    /// Splits the batch into halves and processes interactions:
    /// - Within the left half (recursive)
    /// - Within the right half (recursive)
    /// - Between left and right halves (cross-interactions)
    fn process_batch(&self, slice: &mut [B], base_idx: usize, cutoff: f64) {
        let len = slice.len();

        // Base case: if the slice is small, process sequentially.
        // We use a safe splitting mechanism to modify both i and j.
        if len <= 64 {
            self.process_sequential(slice, base_idx, cutoff);
        } else {
            let mid = len / 2;
            let (left, right) = slice.split_at_mut(mid);

            let left_base = base_idx;
            let right_base = base_idx + mid;

            // Process internal interactions in parallel
            // rayon::join executes two closures potentially in parallel
            rayon::join(
                || self.process_batch(left, left_base, cutoff),
                || self.process_batch(right, right_base, cutoff),
            );

            // Process cross interactions between left and right in parallel
            self.process_cross(left, right, left_base, right_base, cutoff);
        }
