    /// Processes interactions within a small slice sequentially.
    /// Uses `split_at_mut` to safely obtain mutable references to two distinct elements.
    fn process_sequential(&self, slice: &mut [B], base_idx: usize, cutoff: f64) {
        let len = slice.len();
        for i in 0..len {
            // Iterate only over j > i to avoid duplicate checks and self-comparison
            for j in (i + 1)..len {
                // We need to access slice[i] and slice[j] mutably.
                // Since we cannot index mutably twice into the same slice directly,
                // we split the slice around the indices.

                // Split into [0..j] and [j..]
                let (left_part, right_part) = slice.split_at_mut(j);
                let elem_j = &mut right_part[0]; // This is slice[j]

                // From the left part [0..j], split into [0..i] and [i..]
                // Note: i < j is guaranteed by the loop range
                let (_, mid_part) = left_part.split_at_mut(i);
                let elem_i = &mut mid_part[0]; // This is slice[i]

                if elem_i.criterion(elem_j) < cutoff {
                    elem_i.nb.push(base_idx + j);
                    elem_j.nb.push(base_idx + i);
                }
            }
