  "main.rs": "/// Tokenizes a shell command string in a quote-aware fashion.
/// This implementation handles single quotes and whitespace delimiters,
/// mimicking how Bash splits arguments.
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_quote = false;
    // Tracks if we are currently building a token (either chars or quotes).
    // This is necessary to distinguish between "no token" and an empty token "''".
    let mut in_token = false;

    for ch in input.chars() {
        match (in_quote, ch) {
            // Case 1: Inside single quotes
            (true, '\'') => {
                // Closing quote found
                in_quote = false;
                // We remain `in_token`, but do not push the quote char.
            }
            (true, _) => {
                // Regular char inside quotes, preserve literally
                current_token.push(ch);
            }

            // Case 2: Outside single quotes
            (false, '\'') => {
                // Opening quote found
                in_quote = true;
                in_token = true;
            }
            (false, c) if c.is_whitespace() => {
                // Whitespace acts as a delimiter only if not quoted
                if in_token {
                    tokens.push(current_token);
                    current_token = String::new();
                    in_token = false;
                }
            }
            (false, c) => {
                // Regular char outside quotes
                current_token.push(c);
                in_token = true;
            }
        }
    }

    // If the string ends while we are still building a token, push it.
    // (This handles the last token, or tokens ending with a closing quote).
    if in_token {
        tokens.push(current_token);
    }

    tokens
}

