    // The idiomatic way to broadcast in nalgebra is to iterate over columns
    // and subtract the corresponding scalar mean from each column vector.
    let mut centered = matrix.clone();

    for i in 0..matrix.ncols() {
        // We retrieve a mutable view of the i-th column and subtract the scalar mean[i]
        centered.column_mut(i) -= mean[i];
    }

    println!("\nCentered Matrix:\n{}", centered);

    // Verification: The mean of the centered matrix should be close to zero
    println!("\nVerification (Mean of centered matrix):\n{}", centered.column_mean());
