fn Point(id: usize, initial_x: f64, initial_y: f64, color: String) -> Element {
    let ctx = use_context::<DragContext>();

    // Local state for the point's position
    // This persists across renders
    let mut pos = use_signal(|| (initial_x, initial_y));

    // This effect acts as a 'custom event listener'.
    // It subscribes to DragContext updates efficiently.
    //
