    // 1. It always reads `active_id`.
    // 2. IF `active_id` == self.id, it reads `mouse_pos`.
    // 3. IF `active_id` != self.id, it does NOT read `mouse_pos`.
    //
    // This ensures this component only re-runs/re-renders when:
    // - The active drag state changes (anyone starts/stops dragging)
    // - The mouse moves ONLY IF this specific component is being dragged.
    use_effect(move || {
        let active = ctx.active_id.read();

        if active.map_or(false, |aid| aid == id) {
            // We are the active element. Read mouse position and update local state.
            let (mx, my) = *ctx.mouse_pos.read();
            pos.set((mx, my));
        }
    });

