                e.stop_propagation();
                e.prevent_default();
                ctx.active_id.set(Some(id));
                // Snap center to mouse immediately
                let coords = e.element_coordinates();
                pos.set((coords.x as f64, coords.y as f64));
            },
        }
    }
}
