const SEED: u64 = 4174800045971885562;

const fn generate_zobrist_seeds() -> [u64; 781] {
    // We use a simple XorShift64 algorithm which is easy to implement
    // in a const fn and provides sufficient randomness for Zobrist hashing.
    struct ConstRng {
        state: u64,
    }

    impl ConstRng {
        const fn new(seed: u64) -> Self {
            // XorShift state must not be zero
            Self {
                state: if seed == 0 { 1 } else { seed },
            }
        }

        const fn next_u64(&mut self) -> u64 {
            // XorShift64 algorithm
            let mut x = self.state;
            x ^= x << 13;
