// it references is owned by the same struct is to use `ouroboros`.
// Standard Rust lifetimes cannot express self-referential structs safely.
#[self_referencing(derive(Debug, Clone, Hash, Eq, PartialEq))]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default + Hash + Eq,
{
    // The owner of the data.
    // This field must come before fields that borrow from it.
    dynamic_type: R::DynamicType,

    // The name field (owned).
    name: String,

    // Fields borrowing from `dynamic_type`.
    // `borrows` indicates the dependency.
    #[borrows(dynamic_type)]
    group: Option<Cow<'this, str>>,

    #[borrows(dynamic_type)]
    kind: Cow<'this, str>,

    // PhantomData is independent.
    type_: PhantomData<R>,
}

