// -------------------------------------------------------------------
// 1. Define the Trait
// -------------------------------------------------------------------

/// A trait to check if a target struct matches a filter struct.
/// The filter struct has the same type, but fields with `None` are ignored.
pub trait MatchesFilter {
    fn matches_filter(&self, filter: &Self) -> bool;
}

// -------------------------------------------------------------------
// 2. Implement Trait for Primitives and Standard Types
// -------------------------------------------------------------------

// Implementation for Option: This is the core of the recursion logic.
// If the filter is None, it matches everything (no condition).
// If the filter is Some, the target must be Some and the inner values must match.
impl<T: MatchesFilter> MatchesFilter for Option<T> {
    fn matches_filter(&self, filter: &Self) -> bool {
        match filter {
            None => true, // No filter condition provided, so it matches
            Some(filter_val) => {
                match self {
                    None => false, // Filter requires a value, but target is None
                    Some(self_val) => self_val.matches_filter(filter_val),
                }
            }
        }
    }
