        .map_err(|e| format!("Failed to parse naive datetime: {:?}", e))?;

    // Assume the time is UTC and convert to a DateTime<Utc>
    let datetime_utc = naive_dt.and_utc();

    // Return the timestamp. 
    // Using timestamp_millis() to preserve the sub-second precision seen in the input.
    // If you specifically need seconds, use .timestamp().
    Ok(datetime_utc.timestamp_millis())
