/// Middleware to check the Origin header for WebSocket upgrade requests.
async fn check_ws_origin<B>(req: Request<B>, next: Next<B>) -> Result<Response, StatusCode> {
    // Check if this is a WebSocket upgrade request
    let is_ws_upgrade = req
        .headers()
        .get(header::UPGRADE)
        .and_then(|v| v.to_str().ok())
        .map(|v| v.to_lowercase() == "websocket")
        .unwrap_or(false);

    if is_ws_upgrade {
        // Validate the Origin header
        let origin = req.headers().get(header::ORIGIN);

        match origin {
            Some(origin_val) => {
                // Ensure the origin matches our allowed list
                if origin_val != ALLOWED_ORIGIN {
                    tracing::warn!(
                        "Rejected WS connection from invalid origin: {:?}",
                        origin_val
                    );
                    return Err(StatusCode::FORBIDDEN);
                }
                tracing::info!("Accepted WS connection from valid origin");
            }
            None => {
                // Browsers always send Origin for cross-site WS.
                // If it's missing, it might be a non-browser client or a same-origin request.
                // Depending on your policy, you might want to reject this too.
                // For this example, we enforce the presence of the header.
                tracing::warn!("Rejected WS connection: missing Origin header");
                return Err(StatusCode::FORBIDDEN);
            }
        }
    }

    // Proceed to the next layer/handler
    Ok(next.run(req).await)
}

/// The actual WebSocket handler.
/// The Origin check has already happened in the middleware layer.
async fn ws_handler(ws: WebSocketUpgrade) -> Response {
    ws.on_upgrade(|socket| async {
        // Simple echo logic for demonstration
        let (mut tx, mut rx) = socket.split();
        while let Some(msg) = rx.recv().await {
            if let Ok(msg) = msg {
                if tx.send(msg).await.is_err() {
                    break;
                }
            } else {
                break;
            }
        }
    })
}
