/// Rewrites a single UseTree.
/// `parent_segments`: The path segments leading up to this tree from the parent.
/// Returns a Vec of UseTrees because flattening can turn one tree into multiple siblings
/// (e.g., `devices::{a, b}` -> `a, b` if `devices` is stripped).
fn rewrite_use_tree(tree: &ast::UseTree, parent_segments: Vec<String>) -> Vec<ast::UseTree> {
    // 1. Determine the full path of this node
    let mut current_segments = parent_segments.clone();
    let mut has_path = false;

    if let Some(path) = tree.path() {
        has_path = true;
        for seg in path.segments() {
            if let Some(name) = seg.name_ref() {
                current_segments.push(name.text().to_string());
            }
        }
    }

    // 2. Apply transformation logic: `vexide::devices` -> `vexide`
    // We search for the pattern in the full path.
    let new_segments = apply_path_transform(&current_segments);

    // 3. Calculate the suffix (the part of the path belonging to THIS node)
    let suffix_len = if has_path {
        tree.path().unwrap().segments().count()
    } else {
        0
    };

    // The segments that this node "owns" after transformation.
    // If the path length increased (impossible here) or decreased, we adjust.
    // Since we are only removing segments, the suffix might shrink or stay same.
    // The suffix starts at `parent_segments.len()` in the `new_segments` list.
    let my_segments_start = parent_segments.len();
    let my_segments_end = new_segments.len();

    // This is the list of segments we need to materialize in THIS node.
    let my_segments: Vec<String> = new_segments[my_segments_start..my_segments_end].to_vec();

    // 4. Handle children (Recursion)
    // If the node has a use_tree_list (e.g., `vexide::{a, b}`), we recurse.
    // The children need to know the full path up to this point (which is `new_segments`)..
    let mut new_children_trees = Vec::new();
    if let Some(list) = tree.use_tree_list() {
        for child_tree in list.use_trees() {
            let rewritten = rewrite_use_tree(&child_tree, new_segments.clone());
            new_children_trees.extend(rewritten);
        }
    }

    // 5. Construct the resulting node(s)
    // Case A: The node has children. 
    // We need to combine `my_segments` (path) + `new_children_trees` (list).
    // If `my_segments` is empty, it means this node's path was completely consumed (e.g. `use devices;` inside `use vexide::devices;`).
    // In that case, we just return the children (lift them up).

    let star_token = tree.star_token();
    let alias = tree.rename(); // preserve alias if any

    if !new_children_trees.is_empty() {
        // We have children to host.
        if my_segments.is_empty() {
            // Path collapsed completely. Return children.
            // NOTE: If there was an alias `as X` on this node, it's technically lost here.
            // This matches the logic of flattening.
            // If we had a star `*`, and path collapsed, it usually means `use vexide::devices::*;` -> `use vexide::*;`
            // `new_children` is empty for `*` nodes, handled below. 
            // But if it was `use devices::{a,b}`, `new_children` has `a, b`.
            return new_children_trees;
        } else {
            // We have a path and children.
            let path = make::path_from_segments(my_segments.iter().map(|s| s.as_str()));
            let new_list = make::use_tree_list(new_children_trees);
            let new_tree = make::use_tree(Some(path), Some(new_list), alias, None);
            return vec![new_tree];
        }
    }

    // Case B: No children (Leaf node, possibly with star or just a path)
    if let Some(_star) = star_token {
        if my_segments.is_empty() {
            // `use vexide::devices::*;` -> `use vexide::*;`
            // If path became empty, it implies `use *`, which is invalid.
            // But `vexide::devices` -> `vexide` is not empty.
            // If `devices` was root and vanished, `use *` is invalid.
            // Let's assume valid output for this exercise.
            // We can't easily return a "*" without a path context unless we handle it at parent.
            // Since `my_segments` is empty, we return a special tree that is just `*`? 
            // `make::use_tree` handles `path: None`.
            return vec![make::use_tree(None, None, None, Some(make::tokens::star()))];
        } else {
            let path = make::path_from_segments(my_segments.iter().map(|s| s.as_str()));
            return vec![make::use_tree(Some(path), None, alias, Some(make::tokens::star()))];
        }
    }

    // Case C: Simple path `use a::b`
    if !my_segments.is_empty() {
        let path = make::path_from_segments(my_segments.iter().map(|s| s.as_str()));
        return vec![make::use_tree(Some(path), None, alias, None)];
    }

    // Case D: Empty? 
    // This might happen if `use devices;` -> `use ;` (removed).
    // Return empty vec to delete.
    Vec::new()
}

fn apply_path_transform(segments: &[String]) -> Vec<String> {
    let mut result = segments.to_vec();

    // Look for "vexide" followed by "devices"
    let mut i = 0;
    while i + 1 < result.len() {\n        if result[i] == "vexide" && result[i+1] == "devices" {
            // Remove "devices"
            result.remove(i + 1);
            // Continue checking, though we expect only one such pattern usually.
            // Don't increment i here because we want to check the new segment at i+1
            // (though unlikely to be another 'devices' immediately in this specific rule).
        } else {
            i += 1;
        }
    }
    result
}"
