impl Serialize for PropertyValues {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        use serde::ser::SerializeMap;
        let mut map = serializer.serialize_map(None)?;
        match self {
            PropertyValues::Title(val) => map.serialize_entry("title", val)?,
            PropertyValues::Url(val) => map.serialize_entry("url", val)?,
            PropertyValues::MultiSelect(val) => map.serialize_entry("multi_select", val)?,
