            // We want a rotation that:
            // a) Rotates the gizmo's 'Z' (forward) axis to align with the World Normal.
            // b) Preserves the rotation of the cube (so edges align).
            // 
            // The solution is to combine the cube's rotation with a rotation that maps the 
            // local 'face normal' to the gizmo's 'forward' direction.
            // 
            // Gizmo starts facing +Z.
            // Cube's face has a local normal (e.g., +X, +Y, +Z).
            // 
            // Rotation = CubeRotation * RotationArc(LocalFaceNormal, Vec3::Z)
            // However, since the gizmo faces Z, we want to map Vec3::Z to LocalFaceNormal.
            // Let's construct the rotation that rotates the gizmo to align with the local face.

            // We compute the rotation needed to turn the Z-axis into the local normal.
            // This rotation aligns the face.
            let rotation_to_face = Quat::from_rotation_arc(Vec3::Z, local_normal);

            // Combine rotations: 
            // 1. `rotation_to_face`: Rotates the gizmo from its default Z-facing pose to the face's orientation (in local space).
            // 2. `cube_transform.rotation`: Rotates that local alignment into world space.
            let final_rotation = cube_transform.rotation * rotation_to_face;

            // Draw the gizmo
            gizmos.rect(
                Transform::from_translation(face_center)
                    .with_rotation(final_rotation)
                    .to_isometry(),
                Vec2::splat(0.95), // Slightly smaller than the block
                Color::WHITE,
            );

            // Visualize the normal for clarity
            gizmos.arrow(face_center, face_center + world_normal * 0.5, Color::srgb(1.0, 0.0, 0.0));
        }
    }
}

// Helper to find which face was hit based on the local hit point position
fn calculate_local_normal(point: Vec3, aabb: &Aabb) -> Vec3 {
    let center = aabb.center();
    let half_extents = aabb.half_extents();

    // Determine which face of the AABB was hit by checking which coordinate 
    // is closest to the extents.
    let d = point - center;

    let mut abs_x = d.x.abs();
    let mut abs_y = d.y.abs();
    let mut abs_z = d.z.abs();

    // Normalize by half extents to handle non-cubes correctly
    abs_x /= half_extents.x;
    abs_y /= half_extents.y;
    abs_z /= half_extents.z;

    if abs_x > abs_y && abs_x > abs_z {
        Vec3::X * d.x.signum()
    } else if abs_y > abs_z {
        Vec3::Y * d.y.signum()
    } else {
        Vec3::Z * d.z.signum()
    }
}
"
