            // 4. Set the size of the shared memory object
            if libc::ftruncate(fd, size as i64) < 0 {
                libc::close(fd);
                panic!("Failed to ftruncate shared memory");
            }

            // 5. Map the shared memory into our address space
            let ptr = libc::mmap(
                ptr::null_mut(),
                size,
                libc::PROT_WRITE,
                libc::MAP_SHARED,
                fd,
                0,
            );

            if ptr == libc::MAP_FAILED {
                libc::close(fd);
                panic!("Failed to mmap shared memory");
            }

            // Cast pointer to a byte slice for easy writing
            let buffer = std::slice::from_raw_parts_mut(ptr as *mut u8, size);

