/// This function listens for Unix signals.
/// It uses `nix::poll` to wait on either the signal file descriptor
/// or a "stop" pipe. This allows it to block efficiently but wake up
/// immediately when a stop is requested.
fn yield_signals(sender: Sender<Message>, stop_receiver: Receiver<()>) {
    // Create a pipe to act as the "stop" event file descriptor
    // We use a pipe because `poll` works with file descriptors, not channels.
    let (stop_read, mut stop_write) = nix::unistd::pipe().unwrap();

    // Spawn a thread that writes to the pipe when the channel receives a stop signal
    // This bridges the `std::sync::mpsc::Receiver` world with the `fd` world.
    thread::spawn(move || {
        let _ = stop_receiver.recv(); // Block until stop signal
        let _ = nix::unistd::write(stop_write, b"1"); // Write dummy data to wake up poll
    });

    let mut signals = Signals::new(&[SIGINT, SIGTERM, SIGUSR1]).unwrap();
    let signal_fd = signals.as_raw_fd();
    let stop_fd = stop_read;

    let mut fds = [
        PollFd::new(signal_fd, PollFlags::POLLIN),
        PollFd::new(stop_fd, PollFlags::POLLIN),
    ];

    loop {
        // `poll` blocks until one of the FDs has activity
        // This is the key to avoiding the "blocking forever" problem.
        match poll(&mut fds, -1) {
            Ok(_) => {
                // Check if signal received
                if fds[0].revents().unwrap().contains(PollFlags::POLLIN) {
                    for sig in signals.pending() {
                        if sender.send(Message::Signal(sig)).is_err() {
                            return; // Channel closed
                        }
                    }
                }
                // Check if stop signal received
                if fds[1].revents().unwrap().contains(PollFlags::POLLIN) {
                    // Stop requested, break the loop
                    break;
                }
            }
            Err(e) => {
                eprintln!("Poll error: {}", e);
                break;
            }
        }
    }
}

/// This function listens for keyboard input.
/// It uses `termion::async_stdin` to get a non-blocking reader.
/// It polls the reader with a timeout, allowing it to check the stop channel
/// periodically without blocking indefinitely.
fn yield_keys(sender: Sender<Message>, stop_receiver: Receiver<()>) {
    let mut stdout = io::stdout().into_raw_mode().unwrap();

    // `async_stdin` creates a non-blocking reader for stdin
    let mut stdin = termion::async_stdin().keys();

    loop {
        // 1. Check if we should stop
        // `try_recv` is non-blocking
        if stop_receiver.try_recv().is_ok() {
            break;
        }

        // 2. Try to read a key
        // Since stdin is async, `next()` won't block the thread indefinitely
        // However, the iterator interface might still wait. 
        // We rely on the loop structure + sleep to throttle checks.
        match stdin.next() {\            Some(Ok(key)) => {\                if sender.send(Message::Key(key)).is_err() {
                    break; // Channel closed
                }
            }
            Some(Err(e)) => {\                eprintln!("Input error: {}", e);
            }
            None => {
                // No input available yet
                // Sleep a short duration to prevent busy-looping (CPU spin)
                thread::sleep(Duration::from_millis(50));
            }
        }
    }

    // Restore terminal mode on exit
    drop(stdout);
}

fn main() {
    let (sender, receiver) = mpsc::channel();

    // Create stop channels
    let (stop_tx_keys, stop_rx_keys) = mpsc::channel();
    let (stop_tx_signals, stop_rx_signals) = mpsc::channel();

    println!("Program started. Press 'q' to quit, or Ctrl+C for signal.");

    // Spawn threads
    let signal_sender = sender.clone();
    let signal_thread = thread::spawn(move || {
        yield_signals(signal_sender, stop_rx_signals);
    });

    let key_thread = thread::spawn(move || {
        yield_keys(sender, stop_rx_keys);
    });

    // Main event loop
    for msg in receiver.iter() {
        match msg {
            Message::Key(key) => {
                println!("Key pressed: {:?}\r", key);
                if key == Key::Char('q') {
                    println!("Quitting...\r");
                    // Send stop signals to threads
                    let _ = stop_tx_keys.send(());
                    let _ = stop_tx_signals.send(());
                    break;
                }
            }
            Message::Signal(sig) => {
                println!("Received signal: {}\r", sig);
                if sig == SIGINT || sig == SIGTERM {
                    // Send stop signals to threads
                    let _ = stop_tx_keys.send(());
                    let _ = stop_tx_signals.send(());
                    break;
                }
            }
            _ => {}
        }
    }

    // Wait for threads to finish cleanly
    signal_thread.join().unwrap();
    key_thread.join().unwrap();

    println!("Program exited cleanly.\r");
}
"
}
