use tokio::sync::OnceCell;
use tokio_postgres::{Client, Error, NoTls};

#[derive(Debug)]
pub struct DbConfig {
    pub port: u16,
    pub name: String,
    pub user: String,
    pub postgres_password: String,
    pub db_password: String,
}

pub struct DbContainer {
    container_name: String,
    args: Vec<String>,
    db_config: DbConfig,
    // We use OnceCell to cache the client to the default database (postgres)
    client: OnceCell<Client>,
}

impl DbContainer {
    pub fn new<N>(container_name: N, db_config: DbConfig) -> Self
    where
        N: Into<String>,
    {
        Self {
            container_name: container_name.into(),
            args: vec![
                "--env".to_string(),
                format!("POSTGRES_PASSWORD={}", &db_config.postgres_password),
                "--publish".to_string(),
                format!("{}:5432", db_config.port),
            ],
            db_config,
            client: OnceCell::const_new(),
        }
    }

    pub async fn create_database(&self, name: &str) -> Result<(), Error> {
        // Connect to default DB to create the new DB
        let client = self.connect(None).await?;
        client
            .execute(&format!("CREATE DATABASE {name}"), &[])
            .await?;

        // Connect to the new DB to run schema
        let client = self.connect(Some(name)).await?;
        // Placeholder for schema loading
        client.batch_execute("SELECT 1").await
    }

    pub async fn drop_database(&self, name: &str) -> Result<u64, Error> {
        let client = self.connect(None).await?;
        let terminate_sql = format!(
            "
            SELECT pg_terminate_backend(pid)
            FROM pg_stat_activity
            WHERE datname = '{}' AND pid <> pg_backend_pid();
            ",
            name
        );
        client.execute(&terminate_sql, &[]).await?;
        client.execute(&format!("DROP DATABASE {name}"), &[]).await
    }

    async fn connect(&self, db_name: Option<&str>) -> Result<Client, Error> {
        let mut conn_str = format!(
            "host=localhost port={} user=postgres password={}",
            self.db_config.port, self.db_config.postgres_password
        );

        // If a specific database is requested (not the default maintenance DB),
        // create a fresh connection. These are typically short-lived operations
        // (like running a migration), so caching them is less critical.
        if let Some(dbname) = db_name {
            conn_str.push_str(&format!(" dbname={dbname}"));
            let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

            tokio::spawn(async move {
                if let Err(e) = conn.await {
                    eprintln!("Connection error: {e}");
                }
            });

            return Ok(client);
        }

        // For the default connection (used for creating/dropping DBs), cache it.
        // get_or_try_init ensures we connect only once.
        let client = self
            .client
            .get_or_try_init(|| async {
                let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

                // Spawn the connection driver task
                tokio::spawn(async move {
                    if let Err(e) = conn.await {
                        eprintln!("Connection error: {e}");
                    }
                });
                Ok(client)
            })
            .await?;

        // Return a clone of the cached Client.
        // tokio_postgres::Client is backed by an Arc, so cloning is cheap
        // and creates a new handle to the same underlying connection.
        Ok(client.clone())
    }
}

