use std::thread;
use std::time::Duration;

use expectrl::session::Session;
use nix::poll::{poll, PollFd, PollFlags};

/// Represents the running agent process.
/// We use Arc<Mutex> for the Session because expectrl::Session is not Clone,
/// and we need to share it between the Tauri "send" command and the reader thread.
struct Agent {
    session: Arc<Mutex<Session>>,
}

impl Agent {
    pub fn new() -> Result<Self, String> {
        // Spawn a shell. You can replace "bash" with your specific CLI (e.g., "codex", "gemini")
        let session = Session::spawn("bash").map_err(|e| e.to_string())?;
        let session_arc = Arc::new(Mutex::new(session));

        // Clone the Arc for the reader thread
        let reader_session = session_arc.clone();

        // Spawn the reader thread
        thread::spawn(move || {
            let mut buf = [0u8; 4096];

            // Get the raw file descriptor to poll.
            // We must release the lock before calling poll() to prevent deadlock.
            let fd = {
                let guard = reader_session.lock().unwrap();
                guard.as_raw_fd()
            };

            let mut poll_fds = [PollFd::new(fd, PollFlags::POLLIN)];

            loop {
                // 1. Poll for data without holding the mutex.
                // This blocks the thread until data is available, but allows other threads
                // (like the UI sending input) to lock the mutex and write to the PTY.
                match poll(&mut poll_fds, -1) {
                    Ok(_) => {},
                    Err(e) => {
                        eprintln!("Poll error: {}", e);
                        break;
                    }
                }

                // 2. Data is ready. Acquire lock to read.
                let mut guard = match reader_session.lock() {
                    Ok(g) => g,
                    Err(_) => break, // Session poisoned/dropped
                };

                // Check for POLLHUP (process termination)
                if poll_fds[0].revents().map_or(false, |ev| ev.contains(PollFlags::POLLHUP)) {
                    println!("[Process terminated]");
                    break;
                }

                // Read the data
                match guard.read(&mut buf) {
                    Ok(0) => {
                        // EOF
                        println!("[Process terminated]");
                        break;
                    }
                    Ok(n) => {
                        // Emit output to "Frontend" (stdout in this demo)
                        let out = String::from_utf8_lossy(&buf[..n]);
                        print!("{}", out);
                        let _ = io::stdout().flush();
                    }
                    Err(e) => {
                        if e.kind() != io::ErrorKind::WouldBlock {
                            eprintln!("Read error: {}", e);
                            break;
                        }
                    }
                }
                // Lock is released here at the end of the scope
            }
        });

        Ok(Self { session: session_arc })
    }

    /// Called from the UI (stdin in this demo)
    pub fn send(&self, data: &str) {
        let mut guard = match self.session.lock() {
            Ok(g) => g,
            Err(_) => return,
        };

        // Write data to the PTY
        if let Err(e) = guard.write_all(data.as_bytes()) {
            eprintln!("Write error: {}", e);
        }
    }
}

fn main() -> Result<(), String> {
    println!("Starting agent... Type input and press Enter to send.");
    let agent = Agent::new()?;

