        // This blocks the main thread waiting for user input,
        // but the reader thread runs concurrently.
        if stdin.read_line(&mut input).is_err() {
            break;
        }

        // Send the input to the PTY
        // Note: read_line keeps the newline, which is good for shells
        agent.send(&input);
    }

