// -------------------------------------------------------------------
// 1. The Context Object
// -------------------------------------------------------------------
// This represents the context you pass through your Pingora proxy.
// We store the `Span` handle here. `Span` is `Clone + Send + Sync`,
// making it safe to share across threads and async tasks.
struct RequestContext {
    request_id: u64,
    // This is the "Rehydration" token. 
    // It holds a reference to the span data, even if the span is not currently
    // active in the thread-local context.
    root_span: Span,
