// -------------------------------------------------------------------

// Simulates an async stage running on a different thread/task.
// Notice we do NOT rely on `#[instrument]` to automatically pick up the parent,
// because the thread-local context is empty when this task starts.
async fn run_stage_1(ctx: Arc<RequestContext>) {
    // REHYDRATION STRATEGY:
    // Explicitly set the parent of this new span using the stored context.
    let stage_span = info_span!(parent: &ctx.root_span, "stage_1_processing");

    // Use `.instrument()` to attach the span to the async block.
    // This ensures the span is entered every time the future is polled,
    // solving the issue of execution jumping between threads.
    async {
