        info!("Finished stage 1");
    }.instrument(stage_span).await;
}

async fn run_stage_2(ctx: Arc<RequestContext>) {
    // Again, explicitly link to the parent stored in context
    let stage_span = info_span!(parent: &ctx.root_span, "stage_2_upstream");

    async {
        info!("Connecting to upstream...");
        tokio::time::sleep(std::time::Duration::from_millis(50)).await;
        info!("Upstream response received");
    }.instrument(stage_span).await;
}

// -------------------------------------------------------------------
// 3. Main Simulation
// -------------------------------------------------------------------

#[tokio::main]
async fn main() {
    // Setup a subscriber that prints hierarchical spans.
    // `with_target(false)` and `with_span_events` makes the output readable.
    tracing_subscriber::fmt()
        .with_max_level(tracing::Level::INFO)
        .with_span_events(FmtSpan::ENTER | FmtSpan::CLOSE)
        .with_target(false)
        .init();

