use rustyline::DefaultEditor;

fn main() -> rustyline::Result<()> {
    let mut rl = DefaultEditor::new()?;

    // NOTE: We avoid binding keys to `Cmd::Newline` here.
    // `Cmd::Newline` inserts a newline character into the buffer of the current 
    // `readline` call. Since the prompt is an argument to `readline`, it cannot 
    // be changed while inside that call.
    //
    // To display a continuation prompt (e.g., "... "), we must allow the 
    // current `readline` call to finish (return the line), and then start a new 
    // `readline` call with the new prompt.

    let mut buffer = String::new();

    loop {
        // Determine which prompt to show based on whether we have accumulated input.
        let prompt = if buffer.is_empty() { ">> " } else { "... " };

        let readline = rl.readline(prompt);
        match readline {
            Ok(line) => {
                // Append the new line to our accumulator
                buffer.push_str(&line);
                buffer.push('\n');

                // Check if the input represents a complete command.
                // For this example, we treat the input as complete if braces are balanced.
                if is_input_complete(&buffer) {
                    // "Execute" the command
                    println!("Executing: {}", buffer.trim_end());

                    // Add to history (optional)
                    let _ = rl.add_history_entry(buffer.trim_end().to_string());

                    // Reset for the next command
                    buffer.clear();
                }
                // If input is incomplete (e.g., missing closing brace), 
                // the loop continues, showing the "... " prompt.
            }
            Err(ReadlineError::Interrupted) => {
                println!("Interrupted");
                // Reset buffer on Ctrl-C
                buffer.clear();
            }
            Err(ReadlineError::Eof) => {
                println!("Encountered Eof");
                break;
            }
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }
    Ok(())
}

/// Simple helper to determine if a block of code is "complete".
/// Returns true if braces are balanced.
fn is_input_complete(input: &str) -> bool {
    let mut balance = 0;
    for c in input.chars() {
        match c {
            '{' => balance += 1,
            '}' => balance -= 1,
            _ => (),
        }
    }
    // If balance is 0, we assume the block is complete.
    // Note: This simple logic doesn't handle strings or comments containing braces.
    balance == 0
}
"
}
