use std::task::{Context, Poll};
use tokio::task::JoinHandle;

/// The result of the try_poll function.
enum TryPollResult<X> {
    Ready(X),
    Pending(JoinHandle<X>),
}

/// Tries to poll a future synchronously.
/// If the future is ready, returns the value.
/// If the future is pending, spawns it on the Tokio runtime and returns the handle.
fn try_poll<F>(future: F) -> TryPollResult<F::Output>
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    // We need a Waker to create a Context. 
    // Since we are manually polling, we use a "noop" waker because 
    // if the future returns Pending, we are going to spawn it on the runtime 
    // immediately anyway. The runtime will provide a real waker later.
    let waker = futures::task::noop_waker();
    let mut cx = Context::from_waker(&waker);

    // Pin the future to the heap so we can poll it.
    // We use Box::pin because if the future is Pending, we need to move it 
    // into the spawned task. Box::pin allows us to move the pinned future.
    let mut future = Box::pin(future);

    // Poll the future
    match future.as_mut().poll(&mut cx) {
        Poll::Ready(result) => TryPollResult::Ready(result),
        Poll::Pending => {
            // The future is not ready. Spawn it as a new Tokio task.
            // We move the pinned future into the async block.
            let handle = tokio::spawn(future);
            TryPollResult::Pending(handle)
        }
    }
}

#[tokio::main]
async fn main() {
    // Case 1: A future that completes immediately (Ready)
    println!("--- Testing Immediate Future ---");
    let immediate_future = async { 42 };

    // try_poll is a sync function, we can call it here
    match try_poll(immediate_future) {
        TryPollResult::Ready(val) => {
            println!("Future was ready immediately! Result: {}", val);
        }
        TryPollResult::Pending(handle) => {
            println!("Future was pending, awaiting spawned task...");
            let val = handle.await.unwrap();
            println!("Spawned task finished with: {}", val);
        }
    }

    // Case 2: A future that yields (Pending)
    println!("\n--- Testing Yielding Future ---");
    let yielding_future = async {
        // This causes the future to yield once, returning Pending
        tokio::task::yield_now().await;
        100
    };

    match try_poll(yielding_future) {
        TryPollResult::Ready(val) => {
