    let (camera, camera_transform) = camera_query.single();
    let window = windows.single();

    // Get cursor position
    let Some(cursor_position) = window.cursor_position() else {
        return;
    };

    // Get ray from camera
    let Ok(ray) = camera.viewport_to_world(camera_transform, cursor_position) else {
        return;
    };

    // Check intersection with the cube
    for (cube_transform, cube_aabb) in cube_query.iter() {
        // Transform the ray into the cube's local space for AABB intersection
        let world_to_local = cube_transform.affine().inverse();
        let local_ray_origin = world_to_local.transform_point3(ray.origin);
        let local_ray_direction = world_to_local.transform_vector3(ray.direction);
        let local_ray = Ray::new(local_ray_origin, local_ray_direction);

        // Check intersection
        if let Some(hit) = local_ray.aabb_intersection_at(*cube_aabb) {
            // We have a hit in local space. We need to transform data back to world space.
            // Note: AABB intersection gives just the distance, so we calculate the point manually.
            let local_hit_point = local_ray.get_point(hit);
            let world_hit_point = cube_transform.transform_point(local_hit_point);

            // Calculate the normal in local space, then transform to world space.
            // For a unit cube centered at origin, the normal corresponds to the face we hit.
            // We can determine the face by finding which component of the local point is near +/- 0.5.
            let mut local_normal = Vec3::ZERO;
            let extent = 0.5;

            if (local_hit_point.x - extent).abs() < 0.001 { local_normal = Vec3::X; }
            else if (local_hit_point.x + extent).abs() < 0.001 { local_normal = Vec3::NEG_X; }
            else if (local_hit_point.y - extent).abs() < 0.001 { local_normal = Vec3::Y; }
            else if (local_hit_point.y + extent).abs() < 0.001 { local_normal = Vec3::NEG_Y; }
            else if (local_hit_point.z - extent).abs() < 0.001 { local_normal = Vec3::Z; }
            else if (local_hit_point.z + extent).abs() < 0.001 { local_normal = Vec3::NEG_Z; }

            // Transform normal to world space (use inverse transpose for normals, effectively just rotation for uniform scale)
            let world_normal = cube_transform.transform_vector(local_normal).normalize();

            // --- THE MATH SOLUTION ---
            // We need a rotation that aligns the Gizmo's Z axis with the World Normal,
            // while preserving the cube's relative orientation.

            let block_rotation = cube_transform.compute_transform().rotation;

            // Get the block's local Up vector in World space
            let block_up = block_rotation * Vec3::Y;
            // Get the block's local Right vector in World space
            let block_right = block_rotation * Vec3::X;

            let normal = world_normal;
            let mut right: Vec3;
            let mut up: Vec3;

            // Check if the normal is parallel to the block's Up vector (top/bottom faces)
            if normal.dot(block_up).abs() > 0.999 {
                // If parallel, we align the gizmo's right with the block's right
                right = block_right;
                up = normal.cross(right);
            } else {
                // Otherwise, we align the gizmo's up with the projection of block's up on the plane
                // defined by the normal.
                // To do this, we calculate 'right' as the cross product of 'block_up' and 'normal'
                // This ensures 'right' is perpendicular to the normal AND to the block's tilt.
                right = block_up.cross(normal).normalize();
                up = normal.cross(right);
            }

            // Construct rotation matrix from calculated axes
            // The gizmo's X axis maps to 'right'
            // The gizmo's Y axis maps to 'up'
            // The gizmo's Z axis maps to 'normal'
            let rotation_matrix = Mat3::from_cols(right, up, normal);
            let gizmo_rotation = Quat::from_mat3(&rotation_matrix);

            // Draw the gizmo
            gizmos.rect(
                // Offset slightly to avoid z-fighting
                world_hit_point + world_normal * 0.01,
                gizmo_rotation,
                Vec2::splat(0.9), // Slightly smaller than the block face
                Color::WHITE,
