    let cancel_token = CancellationToken::new();

    println!("Service started. Sending events...");
    println!("Press Ctrl+C to trigger shutdown (drop equivalent).\n");

    // 3. Spawn a task that consumes the stream (simulating an SSE connection)
    let stream_handle = tokio::spawn({
