            let mut stream = factory.all_events(token);

            println!("Consumer: Listening for events...");

            while let Some(result) = stream.next().await {
                match result {
                    Ok(event) => println!("Consumer received: {}", event.message),
                    Err(_) => eprintln!("Consumer encountered an error"),
                }
            }

