use std::arch::x86_64::*;

#[cfg(target_arch = "aarch64")]
use std::arch::aarch64::*;

fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len(), PIXELS_PER_LINE * BYTES_PER_PIXEL);
    let ptr = line_bytes.as_mut_ptr();

    // x86_64 implementation using SSE2 (available on all x86_64 CPUs)
    #[cfg(target_arch = "x86_64")]
    {
        unsafe {
            // Load the two halves of the line (16 bytes each)
            let left = _mm_loadu_si128(ptr as *const __m128i);
            let right = _mm_loadu_si128(ptr.add(16) as *const __m128i);

            // Reverse the 32-bit integers (pixels) within each 128-bit lane.
            // _MM_SHUFFLE(0, 1, 2, 3) creates a mask to reverse the order 0->3, 1->2, etc.
            let mask = _MM_SHUFFLE(0, 1, 2, 3);
            let left_rev = _mm_shuffle_epi32(left, mask);
            let right_rev = _mm_shuffle_epi32(right, mask);

            // Store the swapped halves back to memory
            _mm_storeu_si128(ptr as *mut __m128i, right_rev);
            _mm_storeu_si128(ptr.add(16) as *mut __m128i, left_rev);
        }
        return;
    }

