            // vrev64q_u32: [0, 1, 2, 3] -> [1, 0, 3, 2]
            // vextq_u64: Swaps the 64-bit halves.
            // Combined result: [1, 0, 3, 2] -> [3, 2, 1, 0]
            let left_rev = vreinterpretq_u32_u64(vextq_u64(
                vreinterpretq_u64_u32(vrev64q_u32(left)),
                vreinterpretq_u64_u32(vrev64q_u32(left)),
