    let running = Arc::new(AtomicBool::new(true));

    // Spawn the signal handling thread
    let signal_sender = sender.clone();
    let signal_running = Arc::clone(&running);
    let signal_thread = thread::spawn(move || {
        yield_signals(signal_sender, signal_running);
    });

    // Spawn the key handling thread
    let key_sender = sender;
    let key_running = Arc::clone(&running);
    let key_thread = thread::spawn(move || {
        yield_keys(key_sender, key_running);
    });

    println!("Running. Press 'q' to stop or send SIGINT (Ctrl+C).");

    // Main event loop
    for msg in receiver.iter() {
        match msg {
            Message::Key('q') => {
                println!("Quit key pressed.");
                break;
            }
            Message::Key(k) => {
                println!("Key pressed: {}", k);
            }
            Message::Signal(s) => {
                println!("Signal received: {}", s);
                break;
            }
        }
    }

    // Signal threads to stop
    running.store(false, Ordering::Relaxed);

    // Wait for threads to finish
    signal_thread.join().expect("Signal thread panicked");
    key_thread.join().expect("Key thread panicked");

    println!("Application stopped gracefully.");
}

fn yield_signals(sender: Sender<Message>, running: Arc<AtomicBool>) {
    // We create the Signals iterator, but we do not use .forever()
    // Instead we use .pending() in a loop to respect the running flag.
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();

    while running.load(Ordering::Relaxed) {
        // pending() returns an iterator over signals that have already been received
        // It is non-blocking.
        for sig in signals.pending() {
            if sender.send(Message::Signal(sig)).is_err() {
                return; // Receiver dropped
            }
        }
        // Sleep briefly to avoid busy-waiting
        thread::sleep(Duration::from_millis(50));
    }
    println!("Signal thread exiting.");
}

fn yield_keys(sender: Sender<Message>, running: Arc<AtomicBool>) {
    // We use async_stdin() instead of stdin().events()
    // async_stdin() creates a non-blocking stdin handle.
    let stdin = async_stdin();
    // We create the events iterator from the async stdin.
    // Calling .next() on this iterator will not block if there is no input.
    let mut events = stdin.events();

    while running.load(Ordering::Relaxed) {
        // events.next() returns Option<Result<Event, Error>>
        // If no input is available, it returns None immediately (because of async_stdin).
        match events.next() {
            Some(Ok(event)) => {
                if let termion::event::Event::Key(Key::Char(c)) = event {
                    if sender.send(Message::Key(c)).is_err() {
                        return; // Receiver dropped
                    }
                }
