            Some(Err(e)) => {
                eprintln!("Error reading key: {}", e);
                break;
            }
            None => {
                // No input available, sleep to reduce CPU usage
                thread::sleep(Duration::from_millis(50));
            }
        }
    }
    println!("Key thread exiting.");
}
