{
  "Cargo.toml": "[package]
name = "rustyline_cursor_fix"
version = "0.1.0"
edition = "2021"

[dependencies]
rustyline = "12.0.0"
",
  "main.rs": "use rustyline::config::Configurer;
use rustyline::error::ReadlineError;
use rustyline::highlight::MatchingBracketHighlighter;
use rustyline::history::DefaultHistory;
use rustyline::{
    Cmd, ConditionalEventHandler, Editor, Event, EventContext, EventHandler, KeyEvent,
    Modifiers, Movement, RepeatCount,
};

struct MyEventHandler {
    insert: String,
}

impl MyEventHandler {
    fn new(insert: char) -> MyEventHandler {
        let insert = String::from(insert);
        MyEventHandler { insert }
    }
}

impl ConditionalEventHandler for MyEventHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // We only care about the part of the line before the cursor
        let line_before_cursor = &line[0..pos];

        // Find the index of the last non-whitespace character
        if let Some(index) = line_before_cursor.rfind(|c: char| !c.is_whitespace()) {
            // Calculate the byte offset where whitespace starts
            let ws_start = index + line_before_cursor[index..].chars().next().unwrap().len_utf8();

            // Calculate the number of whitespace characters (not bytes) before the cursor
            let ws_chars = line_before_cursor[ws_start..].chars().count();

            if ws_chars > 0 {
                // We have whitespace to delete.
                // Movement::BackwardChar(n) moves the cursor back n characters.
                // Cmd::Replace will delete the text covered by the movement (the whitespace)
                // and insert the new string. The cursor will be positioned after the inserted text.
                let movement = Movement::BackwardChar(ws_chars as RepeatCount);
                return Some(Cmd::Replace(movement, Some(self.insert.clone())));
            }
        }

        // No whitespace found, just insert the character normally
        Some(Cmd::Insert(self.insert.clone()))
    }
}

fn bind_handler(editor: &mut Editor<MatchingBracketHighlighter, DefaultHistory>, key: char) {
    let event = KeyEvent::new(key, Modifiers::NONE);
    let handler = MyEventHandler::new(key);
    let handler = EventHandler::Conditional(Box::new(handler));
    editor.bind_sequence(event, handler);
}

fn main() -> rustyline::Result<()> {
    println!("SQL Editor. Press Ctrl-D to exit.");

    // Create a helper for highlighting (optional, but good for SQL context)
    let helper = MatchingBracketHighlighter::new();

    // Create the editor
    let mut editor = Editor::new()?;
    editor.set_helper(Some(helper));

    // Bind the handlers for '.' and ','
    bind_handler(&mut editor, '.');
    bind_handler(&mut editor, ',');

    loop {
        let readline = editor.readline("zql> ");
        match readline {
            Ok(line) => {
                editor.add_history_entry(line.as_str())?;
                println!("Line: {}", line);
            }
            Err(ReadlineError::Interrupted) => {
                println!("Interrupted");
                break;
            }
            Err(ReadlineError::Eof) => {
                println!("Encountered Eof");
                break;
            }
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }

    Ok(())
}
"
}
