  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::sync::Arc;
use tokio::sync::mpsc;

// Your context struct
pub struct Context(i32);

// The event enum.
// We use `FnOnce` here to allow consuming captured variables.
// We need the Higher-Ranked Trait Bound (HRTB) `for<'a>` because the returned Future
// borrows the Context passed in at call time.
pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> FnOnce(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send,
        >,
    },
}

// A helper macro to hide the complex boxing logic.
// This allows you to write: send_event!(tx, |ctx| async { ... });
macro_rules! send_event {
    ($sender:expr, |$ctx:ident| $body:block) => {
        let _ = $sender.send(InnerAsyncEvent::DoWithContext {
            block: Box::new(|$ctx: &mut Context| Box::pin(async move $body)),
        });
    };
}

// If you prefer a function, it must take a specific closure type that returns a boxed future.
// Note: You cannot easily take `impl AsyncFnOnce` on stable Rust for this pattern,
// nor can you easily take `impl FnOnce(&mut Context) -> impl Future` because
// the return type depends on the input lifetime (GATs limitation with closures).
// So the function signature still requires the caller to box the future, or use the macro.
pub fn with_context_async<F>(sender: &mpsc::Sender<InnerAsyncEvent>, block: F)
where
    F: for<'a> FnOnce(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
        + Send
        + 'static,
{
    let _ = sender.send(InnerAsyncEvent::DoWithContext { block: Box::new(block) });
}

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel::<InnerAsyncEvent>(32);

    // Spawn the worker task that owns the Context
    tokio::spawn(async move {
        let mut ctx = Context(0);
        println!("Worker: Started with Context({})", ctx.0);

        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    // Call the block, which returns a future borrowing ctx
                    let fut = block(&mut ctx);
                    // Await the future
                    fut.await;
                    println!("Worker: Context is now {}", ctx.0);
                }
            }
        }
        println!("Worker: Shutting down");
    });

    // --- Usage ---

    // 1. Using the macro (Cleanest syntax)
    let tx_clone = tx.clone();
    tokio::spawn(async move {
        let external_data = 100;
        send_event!(tx_clone, |ctx| {
            // This async block captures `external_data` by move
            ctx.0 += external_data;
            println!("Task 1: Added 100");
        });
    });

    // 2. Using the function (Requires manual boxing inside the closure)
    let tx_clone = tx.clone();
    tokio::spawn(async move {
        with_context_async(&tx_clone, |ctx| {
            // We must Box::pin the async block here
            Box::pin(async move {
                ctx.0 += 1;
                println!("Task 2: Added 1");
            })
        });
    });

    // 3. Using the function with captured variables
    let tx_clone = tx.clone();
    tokio::spawn(async move {
        let value_to_add = 5;
        with_context_async(&tx_clone, |ctx| {
            // `value_to_add` is moved into this outer closure,
            // then into the async block.
            Box::pin(async move {
                ctx.0 += value_to_add;
                println!("Task 3: Added {}", value_to_add);
            })
        });
    });

    // Drop the original sender so the worker can exit
    drop(tx);

    // Wait a bit for tasks to finish
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
}
"
}
