{
  "Cargo.toml": "[package]
name = "rustyline_replace_fix"
version = "0.1.0"
edition = "2021"

[dependencies]
rustyline = "12.0.0"
",
  "main.rs": "use rustyline::error::ReadlineError;
use rustyline::history::DefaultHistory;
use rustyline::keymap::{Cmd, Movement, RepeatCount};
use rustyline::keys::KeyEvent;
use rustyline::event::{ConditionalEventHandler, Event, EventContext, EventHandler};
use rustyline::Editor;

struct MyEventHandler {
    insert: String,
}

impl MyEventHandler {
    fn new(insert: char) -> MyEventHandler {
        let insert = String::from(insert);
        MyEventHandler { insert }
    }
}

impl ConditionalEventHandler for MyEventHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();
        // We only look at the text before the cursor
        let line_before_cursor = &line[0..pos];

        // Find the amount of whitespace immediately before the cursor.
        // We look for the last non-whitespace character.
        let whitespace_count = match line_before_cursor.rfind(|c: char| !c.is_whitespace()) {
            // If found, the whitespace is between that char and the cursor (pos)
            Some(index) => pos - (index + 1),
            // If not found, the entire line before cursor is whitespace
            None => pos,
        };

        // We use BackwardChar to define the range to replace.
        // If whitespace_count is 0, this effectively becomes an insert at cursor.
        // If > 0, it replaces that many preceding whitespace chars with our text.
        // The Cmd::Replace implementation in rustyline (delete range + insert text)
        // naturally leaves the cursor after the inserted text.
        let movement = Movement::BackwardChar(whitespace_count as RepeatCount);

        Some(Cmd::Replace(movement, Some(self.insert.clone())))
    }
}

fn bind_handler(editor: &mut Editor<(), DefaultHistory>, key: char) {
    let event = KeyEvent::new(key, rustyline::Modifiers::NONE);
    let handler = MyEventHandler::new(key);
    let handler = EventHandler::Conditional(Box::new(handler));
    editor.bind_sequence(event, handler);
}

fn main() -> rustyline::Result<()> {
    // `()` means no helper
    let mut rl = Editor::new()?;

    // Bind the smart handlers for '.' and ','
    bind_handler(&mut rl, '.');
    bind_handler(&mut rl, ',');

    println!("SQL Editor (press Ctrl-D to exit)");
    loop {
        let readline = rl.readline("zql> ");
        match readline {
            Ok(line) => {
                // We don't execute SQL here, just demonstrate line editing
                println!("Line: {}", line);
                rl.add_history_entry(line)?;
            }
            Err(ReadlineError::Interrupted) => {
                println!("Interrupted");
                break;
            }
            Err(ReadlineError::Eof) => {
                println!("Exit");
                break;
            }
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }
    Ok(())
}
"
}
